55	/* stored-key vs. key
56	 * ------------------
57	 * If dictType.keyFromStoredKey is non-NULL, then dict distinguishes between the
58	 * lookup key and the actual stored-key object. In this case, "key" is used to 
59	 * locate entries, while "storedKey" is the actual element stored in the dict.
60	 * If dictType.keyFromStoredKey is NULL, the lookup "key" and the stored-key are the
61	 * same. This API is primarily relevant for no_value=1 dicts, where the key and value
62	 * might be packed together. When values are stored separately, this identity 
63	 * distinction does not arise. The marker __stored_key is used to indicate that 
64	 * the pointer refers to the stored-key rather than the lookup key.
65	 */
66	#define __stored_key
67	
68	typedef struct dictEntry dictEntry; /* opaque */
69	typedef struct dict dict;
70	typedef dictEntry **dictEntryLink; /* See description of dictFindLink() */
71	
72	/* Searching for a key in a dict may involve few comparisons.
73	 * If extracting the looked-up key is expensive (e.g., sdslen(), kvobjGetKey()),  
74	 * caching can be used to reduce those repetitive computations.  
75	 *  
76	 * This struct, passed to the comparison function as temporary caching, if 
77	 * needed by the function across comparison of a given lookup. 
78	 * for the looked-up key and resets before each new lookup. */
79	typedef struct dictCmpCache {
80	    int useCache;
81	    
82	    union {
83	        uint64_t u64;
84	        int64_t i64;
85	        int i;
86	        size_t sz;
87	        void *p;
88	    } data[2];
89	} dictCmpCache;
90	
91	typedef struct dictType {
92	    /* Callbacks */
93	    uint64_t (*hashFunction)(const void *key);
94	    void *(*keyDup)(dict *d, const void *key __stored_key);
95	    void *(*valDup)(dict *d, const void *obj);
96	    int (*keyCompare)(dictCmpCache *cache, const void *key1, const void *key2);
97	    void (*keyDestructor)(dict *d, void *key __stored_key);
98	    void (*valDestructor)(dict *d, void *obj);
99	    int (*resizeAllowed)(size_t moreMem, double usedRatio);
100	    /* Invoked at the start of dict initialization/rehashing (old and new ht are already created) */
101	    void (*rehashingStarted)(dict *d);
102	    /* Invoked at the end of dict initialization/rehashing of all the entries from old to new ht. Both ht still exists
103	     * and are cleaned up after this callback.  */
104	    void (*rehashingCompleted)(dict *d);
105	    /* Invoked when the size of the dictionary changes.
106	     * The `delta` parameter can be positive (size increase) or negative (size decrease). */
107	    void (*bucketChanged)(dict *d, long long delta);
108	    /* Allow a dict to carry extra caller-defined metadata. The
109	     * extra memory is initialized to 0 when a dict is allocated. */
110	    size_t (*dictMetadataBytes)(dict *d);
111	
112	    /* Data */
113	    void *userdata;
114	
115	    /* Flags */
116	    /* The 'no_value' flag, if set, indicates that values are not used, i.e. the
117	     * dict is a set. When this flag is set, it's not possible to access the
118	     * value of a dictEntry and it's also impossible to use dictSetKey(). It 
119	     * enables an optimization to store a key directly without an allocating 
120	     * dictEntry in between, if it is the only key in the bucket. */
121	    unsigned int no_value:1;
122	    /* This flag is required for `no_value` optimization since the optimization
123	     * reuses LSB bits as metadata */ 
124	    unsigned int keys_are_odd:1;
125	
126	    /* Ensures that the entire hash table is rehashed at once if set. */
127	    unsigned int force_full_rehash:1;
128	    
129	    /* Callback to extract key from stored-key object. When set, the dict can
130	     * store keys in one format (e.g., a structure) but look them up using a
131	     * different format, extracted from the stored-key. (e.g., sds or integer). 
132	     * Set to NULL if key and stored-key object are the same. Relevant only for
133	     * no_value=1 dicts. */
134	    const void *(*keyFromStoredKey)(const void *key __stored_key);
135	
136	    /* Optional callback called when the dict is destroyed. */
137	    void (*onDictRelease)(dict *d);
138	
139	    /* Optional prefetch hooks used by the memory_prefetch state machine.
140	     * Both default to NULL; when both are NULL the state machine just
141	     * prefetches the bucket + dictEntry chain and stops there.
142	     *
143	     * prefetchEntryKey: called after a dictEntry has been brought into
144	     *   cache. Returns an address to issue redis_prefetch_read on (so the
145	     *   key payload behind the entry is warm before keyCompare runs), or
146	     *   NULL if nothing extra is needed (e.g. the key is co-located with
147	     *   the entry).
148	     * prefetchEntryValue: called when the entry is the *presumed* match
149	     *   for the lookup key — either keyCompare returned equal, or the
150	     *   state machine took the "last entry in chain, not rehashing"
151	     *   shortcut and is betting on a hit without comparing. Callbacks
152	     *   must therefore not assume the key has been verified equal; the
153	     *   prefetch is advisory. Returns an address to prefetch for the
154	     *   value-side payload, or NULL. */
155	    void *(*prefetchEntryKey)(const dictEntry *de);
156	    void *(*prefetchEntryValue)(const dictEntry *de);
157	} dictType;
