53	/* Create a new array of geoPoints. */
54	geoArray *geoArrayCreate(void) {
55	    geoArray *ga = zmalloc(sizeof(*ga));
56	    /* It gets allocated on first geoArrayAppend() call. */
57	    ga->array = NULL;
58	    ga->buckets = 0;
59	    ga->used = 0;
60	    return ga;
61	}
62	
63	/* Add and populate with data a new entry to the geoArray. */
64	geoPoint *geoArrayAppend(geoArray *ga, double *xy, double dist,
65	                         double score, char *member)
66	{
67	    if (ga->used == ga->buckets) {
68	        ga->buckets = (ga->buckets == 0) ? 8 : ga->buckets*2;
69	        ga->array = zrealloc(ga->array,sizeof(geoPoint)*ga->buckets);
70	    }
71	    geoPoint *gp = ga->array+ga->used;
72	    gp->longitude = xy[0];
73	    gp->latitude = xy[1];
74	    gp->dist = dist;
75	    gp->member = member;
76	    gp->score = score;
77	    ga->used++;
78	    return gp;
79	}
80	
81	/* Destroy a geoArray created with geoArrayCreate(). */
82	void geoArrayFree(geoArray *ga) {
83	    size_t i;
84	    for (i = 0; i < ga->used; i++) sdsfree(ga->array[i].member);
85	    zfree(ga->array);
86	    zfree(ga);
87	}
