61	/* Update LRM when an object is modified. */
62	void updateLRM(robj *o) {
63	    if (o->refcount == OBJ_SHARED_REFCOUNT)
64	        return;
65	    if (server.maxmemory_policy & MAXMEMORY_FLAG_LRM) {
66	        o->lru = LRU_CLOCK();
67	    }
68	}
