193	/* Assert per-slot alloc_size (For debugging only) */
194	static void dbgAssertAllocSizePerSlot(redisDb *db) {
195	    if (!server.memory_tracking_enabled) return;
196	    
197	    /* Check allocsizes histogram per db */
198	    kvstoreMetadata *meta = kvstoreGetMetadata(db->keys);
199	    dbgAssertHist(db->keys, meta->allocsizes_hist, kvobjAllocSize, "dbgAssertAllocsizesHist");
200	    
201	    /* Check alloc_size per slot */    
202	    size_t slot_sizes[CLUSTER_SLOTS] = {0};
203	    dictEntry *de;
204	    kvstoreIterator kvs_it;
205	    kvstoreIteratorInit(&kvs_it, db->keys);
206	    while ((de = kvstoreIteratorNext(&kvs_it)) != NULL) {
207	        int slot = kvstoreIteratorGetCurrentDictIndex(&kvs_it);
208	        kvobj *kv = dictGetKV(de);
209	        slot_sizes[slot] += kvobjAllocSize(kv);
210	    }
211	    kvstoreIteratorReset(&kvs_it);
212	
213	    int num_slots = kvstoreNumDicts(db->keys);
214	    for (int slot = 0; slot < num_slots; slot++) {
215	        kvstoreDictMetadata *dictMeta = kvstoreGetDictMeta(db->keys, slot, 0);
216	        size_t want = slot_sizes[slot];
217	        size_t have = dictMeta ? dictMeta->alloc_size : 0;
218	        if (have == want) continue;
219	        serverPanic("dbgAssertAllocSizePerSlot: slot=%d expected=%zu actual=%zu",
220	                    slot, want, have);
221	    }
222	}
