453	/* Read dbAddInternal() comment */
454	kvobj *dbAdd(redisDb *db, robj *key, robj **valref) {
455	    KeyMetaSpec keyMetaEmpty; /* No metadata added */
456	    keyMetaSpecInit(&keyMetaEmpty);
457	    return dbAddInternal(db, key, valref, NULL, &keyMetaEmpty);
458	}
