474	/* Return slot-specific dictionary for key based on key's hash slot when cluster mode is enabled, else 0.*/
475	int getKeySlot(sds key) {
476	    if (!server.cluster_enabled) return 0;
477	    /* This is performance optimization that uses pre-set slot id from the current command,
478	     * in order to avoid calculation of the key hash.
479	     *
480	     * This optimization is only used when current_client flag `CLIENT_EXECUTING_COMMAND` is set.
481	     * It only gets set during the execution of command under `call` method. Other flows requesting
482	     * the key slot would fallback to calculateKeySlot.
483	     */
484	    if (server.current_client && server.current_client->slot >= 0 && server.current_client->flags & CLIENT_EXECUTING_COMMAND) {
485	        debugServerAssertWithInfo(server.current_client, NULL,
486	                                  (int)keyHashSlot(key, (int)sdslen(key)) == server.current_client->slot);
487	        return server.current_client->slot;
488	    }
489	    int slot = keyHashSlot(key, (int)sdslen(key));
490	    return slot;
491	}
