493	/* Return the slot of the key in the command.
494	 * INVALID_CLUSTER_SLOT if no keys, CLUSTER_CROSSSLOT if cross slot, otherwise the slot number. */
495	int getSlotFromCommand(struct redisCommand *cmd, robj **argv, int argc) {
496	    if (!cmd || !server.cluster_enabled) return INVALID_CLUSTER_SLOT;
497	
498	    /* Get the keys from the command */
499	    getKeysResult result = GETKEYS_RESULT_INIT;
500	    getKeysFromCommand(cmd, argv, argc, &result);
501	
502	    /* Extract slot from the keys result. */
503	    int slot = extractSlotFromKeysResult(argv, &result);
504	    getKeysFreeResult(&result);
505	    return slot;
506	}
