792	/* During atomic slot migration, keys that are being imported are in an
793	 * intermediate state. we cannot access them and therefore skip them.
794	 *
795	 * This callback function now is used by:
796	 * - dbRandomKey
797	 * - keysCommand
798	 * - scanCommand
799	 */
800	static int accessKeysShouldSkipDictIndex(int didx) {
801	    return !clusterCanAccessKeysInSlot(didx);
802	}
