1093	/* Discard tempDb, this can be slow (similar to FLUSHALL), but it's always async. */
1094	void discardTempDb(redisDb *tempDb) {
1095	    int async = 1;
1096	
1097	    /* Release temp DBs. */
1098	    emptyDbStructure(tempDb, -1, async, NULL);
1099	    for (int i=0; i<server.dbnum; i++) {
1100	        /* Destroy sub-expires before deleting the kv-objects since ebuckets
1101	         * data structure is embedded in the stored kv-objects. */
1102	        estoreRelease(tempDb[i].subexpires);
1103	        kvstoreRelease(tempDb[i].keys);
1104	        kvstoreRelease(tempDb[i].expires);
1105	        dictRelease(tempDb[i].stream_idmp_keys);
1106	    }
1107	
1108	    zfree(tempDb);
