1146	/*-----------------------------------------------------------------------------
1147	 * Hooks for key space changes.
1148	 *
1149	 * Every time a key in the database is modified the function
1150	 * keyModified() is called.
1151	 *
1152	 * Every time a DB is flushed the function signalFlushDb() is called.
1153	 *----------------------------------------------------------------------------*/
1154	
1155	/* Called when a key is modified to update LRM timestamp
1156	 * and optionally signal watchers/tracking clients.
1157	 *
1158	 * Arguments:
1159	 * - c: client (may be NULL if the key was modified out of a context of a client)
1160	 * - db: database containing the key
1161	 * - key: the key that was modified
1162	 * - val: the value object (if NULL, LRM won't be updated, e.g., for deleted keys)
1163	 * - signal: if true, trigger WATCH and client-side tracking invalidation
1164	 */
1165	void keyModified(client *c, redisDb *db, robj *key, robj *val, int signal) {
1166	    if (val) updateLRM(val);
1167	    if (signal) {
1168	        touchWatchedKey(db,key);
1169	        trackingInvalidateKey(c,key,1);
1170	    }
1171	}
