1222	/* Flushes the whole server data set. */
1223	void flushAllDataAndResetRDB(int flags) {
1224	    server.dirty += emptyData(-1,flags,NULL);
1225	    if (server.child_type == CHILD_TYPE_RDB) killRDBChild();
1226	    if (server.saveparamslen > 0) {
1227	        rdbSaveInfo rsi, *rsiptr;
1228	        rsiptr = rdbPopulateSaveInfo(&rsi);
1229	        rdbSave(SLAVE_REQ_NONE,server.rdb_filename,rsiptr,RDBFLAGS_NONE);
1230	    }
1231	
1232	#if defined(USE_JEMALLOC)
1233	    /* jemalloc 5 doesn't release pages back to the OS when there's no traffic.
1234	     * for large databases, flushdb blocks for long anyway, so a bit more won't
1235	     * harm and this way the flush and purge will be synchronous. */
1236	    if (!(flags & EMPTYDB_ASYNC)) {
1237	        /* Only clear the current thread cache.
1238	         * Ignore the return call since this will fail if the tcache is disabled. */
1239	        je_mallctl("thread.tcache.flush", NULL, NULL, NULL, 0);
1240	
1241	        jemalloc_purge();
1242	    }
1243	#endif
1244	}
