1246	/* Block client for blocking ASYNC FLUSH operation (FLUSH*, SFLUSH). */
1247	void blockClientForAsyncFlush(client *c) {
1248	    /* measure bg job till completion as elapsed time of flush command */
1249	    elapsedStart(&c->bstate.lazyfreeStartTime);
1250	
1251	    c->bstate.timeout = 0;
1252	    /* We still need to perform cleanup operations for the command, including
1253	     * updating the replication offset, so mark this command as pending to
1254	     * avoid command from being reset during unblock. */
1255	    c->flags |= CLIENT_PENDING_COMMAND;
1256	    blockClient(c, BLOCKED_LAZYFREE);
1257	}
