1259	/* CB function on blocking ASYNC FLUSH/TRIM completion.
1260	 * We will unblock the client and send the proper reply if provided. */
1261	void kvsAsyncFreeDoneCB(uint64_t client_id, void *userdata) {
1262	
1263	    /* If ASM Trim context provided, apply histogram delta */
1264	    asmTrimCtx *ctx = userdata;
1265	    if (ctx) {
1266	        kvstoreMetadata *meta = kvstoreGetMetadata(server.db[0].keys);
1267	        /* Apply histogram delta only if target_kvstore hasn't changed */
1268	        if (ctx->target_kvstore == server.db[0].keys && meta) {
1269	            for (int type = 0; type < MAX_KEYSIZES_TYPES; type++) {
1270	                for (int bin = 0; bin < MAX_KEYSIZES_BINS; bin++) {
1271	                    meta->keysizes_hist[type][bin] -= ctx->delta_keysizes_hist[type][bin];
1272	                    meta->allocsizes_hist[type][bin] -= ctx->delta_allocsizes_hist[type][bin];
1273	                }
1274	            }
1275	        }
1276	        /* Decrement counter unconditionally to track job completion. If kvstore was
1277	         * replaced (e.g., by FLUSHALL), the new histogram is already consistent (reset
1278	         * to 0 for empty DB), so it's safe to resume assertions when counter reaches 0. */
1279	        asmBgTrimCounterDecr();
1280	    }
1281	
1282	    unblockClientForAsyncFlush(client_id, (ctx) ? ctx->slots : NULL);
1283	
1284	    /* Release context and slots */
1285	    asmTrimCtxRelease(ctx);
1286	}
1287	
1288	/* Unblock client on async flush/trim completion */
1289	void unblockClientForAsyncFlush(uint64_t client_id, struct slotRangeArray *slots) {
1290	    client *c = lookupClientByID(client_id);
1291	
1292	    /* Verify that client still exists and being blocked. */
1293	    if (!(c && c->flags & CLIENT_BLOCKED)) {
1294	        return;
1295	    }
1296	
1297	    /* Update current_client (Called functions might rely on it) */
1298	    client *old_client = server.current_client;
1299	    server.current_client = c;
1300	
1301	    /* Don't update blocked_us since command was processed in bg by lazy_free thread */
1302	    updateStatsOnUnblock(c, 0 /*blocked_us*/, elapsedUs(c->bstate.lazyfreeStartTime), 0);
1303	
1304	    /* Only SFLUSH command pass user data pointer. */
1305	    if (slots)
1306	        replySlotsFlush(c, slots);
1307	    else
1308	        addReply(c, shared.ok);
1309	
1310	    /* mark client as unblocked */
1311	    unblockClient(c, 1);
1312	
1313	    if (c->flags & CLIENT_PENDING_COMMAND) {
1314	        c->flags &= ~CLIENT_PENDING_COMMAND;
1315	        /* The FLUSH command won't be reprocessed, FLUSH command is finished, but
1316	         * we still need to complete its full processing flow, including updating
1317	         * the replication offset. */
1318	        commandProcessed(c);
1319	    }
1320	
1321	    /* On flush completion, update the client's memory */
1322	    updateClientMemUsageAndBucket(c);
1323	
1324	    /* restore current_client */
1325	    server.current_client = old_client;
1326	}
