1414	/* This command implements DEL and UNLINK. */
1415	void delGenericCommand(client *c, int lazy) {
1416	    int numdel = 0, j;
1417	
1418	    for (j = 1; j < c->argc; j++) {
1419	        if (expireIfNeeded(c->db, c->argv[j], NULL, 0) == KEY_DELETED)
1420	            continue;
1421	        int deleted  = lazy ? dbAsyncDelete(c->db,c->argv[j]) :
1422	                              dbSyncDelete(c->db,c->argv[j]);
1423	        if (deleted) {
1424	            keyModified(c,c->db,c->argv[j],NULL,1);
1425	            notifyKeyspaceEvent(NOTIFY_GENERIC,
1426	                "del",c->argv[j],c->db->id);
1427	            server.dirty++;
1428	            numdel++;
1429	        }
1430	    }
1431	    addReplyLongLong(c,numdel);
1432	}
