1646	int objectTypeCompare(robj *o, long long target) {
1647	    if (o->type != OBJ_MODULE) {
1648	        if (o->type != target) 
1649	            return 0;
1650	        else 
1651	            return 1;
1652	    }
1653	    /* module type compare */
1654	    moduleType *type = ((moduleValue *)o->ptr)->type;
1655	    long long mt = (long long)REDISMODULE_TYPE_SIGN(type->entity.id);
1656	    if (target != -mt)
1657	        return 0;
