1661	/* This callback is used by scanGenericCommand in order to collect elements
1662	 * returned by the dictionary iterator into a list. */
1663	void scanCallback(void *privdata, const dictEntry *de, dictEntryLink plink) {
1664	    UNUSED(plink);
1665	    Entry *hashEntry = NULL;
1666	    scanData *data = (scanData *)privdata;
1667	    vec *keys = data->keys;
1668	    robj *o = data->o;
1669	    sds val = NULL;
1670	    void *key = NULL;  /* if OBJ_HASH then key is of type `hfield`. Otherwise, `sds` */
1671	    void *keyStr;
1672	    data->sampled++;
1673	
1674	    /* o and typename can not have values at the same time. */
1675	    serverAssert(!((data->type != LLONG_MAX) && o));
1676	
1677	    kvobj *kv = NULL;
1678	    zskiplistNode *znode = NULL;
1679	    if (!o) { /* If scanning keyspace */
1680	        kv = dictGetKV(de);
1681	        keyStr = kvobjGetKey(kv);
1682	    } else if (o->type == OBJ_HASH) {
1683	        hashEntry = dictGetKey(de);
1684	        keyStr = entryGetField(hashEntry);
1685	    } else if (o->type == OBJ_ZSET) {
1686	        znode = dictGetKey(de);
1687	        keyStr = zslGetNodeElement(znode);
1688	    } else {
1689	        keyStr = dictGetKey(de);
1690	    }
1691	    
1692	    /* Filter element if it does not match the pattern. */
1693	    if (data->pattern) {
1694	        if (!stringmatchlen(data->pattern, sdslen(data->pattern), keyStr, sdslen(keyStr), 0)) {
1695	            return;
1696	        }
1697	    }
1698	    
1699	    if (!o) {
1700	        /* Expiration check first - only for database keyspace scanning.
1701	         * Use kv obj to avoid robj creation. */
1702	        if (expireIfNeeded(data->db, NULL, kv, 0) != KEY_VALID)
1703	            return;
1704	
1705	        /* Type filtering - only for database keyspace scanning */
1706	        if (data->typename) {
1707	            /* For unknown types (LLONG_MAX), skip all keys */
1708	            if (data->type == LLONG_MAX)
1709	                return;
1710	            /* For known types, skip keys that don't match */
1711	            if (!objectTypeCompare(kv, data->type))
1712	                return;
1713	        }
1714	    }
1715	
1716	    if (o == NULL) {
1717	        key = keyStr;
1718	    } else if (o->type == OBJ_SET) {
1719	        key = keyStr;
1720	    } else if (o->type == OBJ_HASH) {
1721	        key = keyStr;
1722	        val = entryGetValue(hashEntry);
1723	
1724	        /* If field is expired, then ignore */
1725	        if (entryIsExpired(hashEntry))
1726	            return;
1727	
1728	    } else if (o->type == OBJ_ZSET) {
1729	        char buf[MAX_LONG_DOUBLE_CHARS];
1730	        int len = ld2string(buf, sizeof(buf), znode->score, LD_STR_AUTO);
1731	        key = sdsdup(keyStr);
1732	        val = sdsnewlen(buf, len);
1733	    } else {
1734	        serverPanic("Type not handled in SCAN callback.");
1735	    }
1736	
1737	    vecPush(keys, key);
1738	    if (val && !data->no_values) vecPush(keys, val);
1739	}
