1802	/* This command implements SCAN, HSCAN and SSCAN commands.
1803	 * If object 'o' is passed, then it must be a Hash, Set or Zset object, otherwise
1804	 * if 'o' is NULL the command will operate on the dictionary associated with
1805	 * the current database.
1806	 *
1807	 * When 'o' is not NULL the function assumes that the first argument in
1808	 * the client arguments vector is a key so it skips it before iterating
1809	 * in order to parse options.
1810	 *
1811	 * In the case of a Hash object the function returns both the field and value
1812	 * of every element on the Hash. */
1813	void scanGenericCommand(client *c, robj *o, unsigned long long cursor) {
1814	    int i, j;
1815	    long count = 10;
1816	    sds pat = NULL;
1817	    sds typename = NULL;
1818	    long long type = LLONG_MAX;
1819	    int patlen = 0, use_pattern = 0, no_values = 0;
1820	    dict *ht;
1821	
1822	    /* Object must be NULL (to iterate keys names), or the type of the object
1823	     * must be Set, Sorted Set, or Hash. */
1824	    serverAssert(o == NULL || o->type == OBJ_SET || o->type == OBJ_HASH ||
1825	                o->type == OBJ_ZSET);
1826	
1827	    /* Set i to the first option argument. The previous one is the cursor. */
1828	    i = (o == NULL) ? 2 : 3; /* Skip the key argument if needed. */
1829	
1830	    /* Step 1: Parse options. */
1831	    while (i < c->argc) {
1832	        j = c->argc - i;
1833	        if (!strcasecmp(c->argv[i]->ptr, "count") && j >= 2) {
1834	            if (getLongFromObjectOrReply(c, c->argv[i+1], &count, NULL)
1835	                != C_OK)
1836	            {
1837	                return;
1838	            }
1839	
1840	            if (count < 1) {
1841	                addReplyErrorObject(c,shared.syntaxerr);
1842	                return;
1843	            }
1844	
1845	            i += 2;
1846	        } else if (!strcasecmp(c->argv[i]->ptr, "match") && j >= 2) {
1847	            pat = c->argv[i+1]->ptr;
1848	            patlen = sdslen(pat);
1849	
1850	            /* The pattern always matches if it is exactly "*", so it is
1851	             * equivalent to disabling it. */
1852	            use_pattern = !(patlen == 1 && pat[0] == '*');
1853	
1854	            i += 2;
1855	        } else if (!strcasecmp(c->argv[i]->ptr, "type") && o == NULL && j >= 2) {
1856	            /* SCAN for a particular type only applies to the db dict */
1857	            typename = c->argv[i+1]->ptr;
1858	            type = getObjectTypeByName(typename);
1859	            if (type == LLONG_MAX) {
1860	                /* TODO: uncomment in redis 8.0
1861	                addReplyErrorFormat(c, "unknown type name '%s'", typename);
1862	                return; */
1863	            }
1864	            i+= 2;
1865	        } else if (!strcasecmp(c->argv[i]->ptr, "novalues")) {
1866	            if (!o || o->type != OBJ_HASH) {
1867	                addReplyError(c, "NOVALUES option can only be used in HSCAN");
1868	                return;
1869	            }
1870	            no_values = 1;
1871	            i++;
1872	        } else {
1873	            addReplyErrorObject(c,shared.syntaxerr);
1874	            return;
1875	        }
1876	    }
1877	
1878	    /* Step 2: Iterate the collection.
1879	     *
1880	     * Note that if the object is encoded with a listpack, intset, or any other
1881	     * representation that is not a hash table, we are sure that it is also
1882	     * composed of a small number of elements. So to avoid taking state we
1883	     * just return everything inside the object in a single call, setting the
1884	     * cursor to zero to signal the end of the iteration. */
1885	
1886	    /* Handle the case of a hash table. */
1887	    ht = NULL;
1888	    if (o == NULL) {
1889	        ht = NULL;
1890	    } else if (o->type == OBJ_SET && o->encoding == OBJ_ENCODING_HT) {
1891	        ht = o->ptr;
1892	    } else if (o->type == OBJ_HASH && o->encoding == OBJ_ENCODING_HT) {
1893	        ht = o->ptr;
1894	    } else if (o->type == OBJ_ZSET && o->encoding == OBJ_ENCODING_SKIPLIST) {
1895	        zset *zs = o->ptr;
1896	        ht = zs->dict;
1897	    }
1898	
1899	    vec keys;
1900	    void *keys_stack[256];
1901	    vecInit(&keys, keys_stack, 256);
1902	    /* Hash on dict only has pointers to dict entries; other paths allocate
1903	     * temporary sds that must be released. */
1904	    if (o && (!ht || o->type == OBJ_ZSET))
1905	        vecSetFreeMethod(&keys, sdsfreegeneric);
1906	
1907	    /* For main dictionary scan or data structure using hashtable. */
1908	    if (!o || ht) {
1909	        /* We set the max number of iterations to ten times the specified
1910	         * COUNT, so if the hash table is in a pathological state (very
1911	         * sparsely populated) we avoid to block too much time at the cost
1912	         * of returning no or very few elements. */
1913	        long maxiterations = (count > LONG_MAX / 10) ? LONG_MAX : count * 10;
1914	
1915	        /* We pass scanData which have three pointers to the callback:
1916	         * 1. data.keys: the list to which it will add new elements;
1917	         * 2. data.o: the object containing the dictionary so that
1918	         * it is possible to fetch more data in a type-dependent way;
1919	         * 3. data.type: the specified type scan in the db, LLONG_MAX means
1920	         * type matching is no needed;
1921	         * 4. data.pattern: the pattern string;
1922	         * 5. data.sampled: the maxiteration limit is there in case we're
1923	         * working on an empty dict, one with a lot of empty buckets, and
1924	         * for the buckets are not empty, we need to limit the spampled number
1925	         * to prevent a long hang time caused by filtering too many keys;
1926	         * 6. data.no_values: to control whether values will be returned or
1927	         * only keys are returned. */
1928	        scanData data = {
1929	            .keys = &keys,
1930	            .o = o,
1931	            .type = type,
1932	            .pattern = use_pattern ? pat : NULL,
1933	            .sampled = 0,
1934	            .no_values = no_values,
1935	            .typename = typename,
1936	            .db = c->db,
1937	        };
1938	
1939	        /* A pattern may restrict all matching keys to one cluster slot. */
1940	        int onlydidx = -1;
1941	        if (o == NULL && use_pattern && server.cluster_enabled) {
1942	            onlydidx = patternHashSlot(pat, patlen);
1943	        }
1944	        do {
1945	            /* In cluster mode there is a separate dictionary for each slot.
1946	             * If cursor is empty, we should try exploring next non-empty slot. */
1947	            if (o == NULL) {
1948	                cursor = kvstoreScan(c->db->keys, cursor, onlydidx, scanCallback, scanShouldSkipDict, &data);
1949	            } else {
1950	                cursor = dictScan(ht, cursor, scanCallback, &data);
1951	            }
1952	        } while (cursor && maxiterations-- && data.sampled < count);
1953	    } else if (o->type == OBJ_SET) {
1954	        unsigned long array_reply_len = 0;
1955	        void *replylen = NULL;
1956	        vecRelease(&keys);
1957	        char *str;
1958	        char buf[LONG_STR_SIZE];
1959	        size_t len;
1960	        int64_t llele;
1961	        /* Reply to the client. */
1962	        addReplyArrayLen(c, 2);
1963	        /* Cursor is always 0 given we iterate over all set */
1964	        addReplyBulkLongLong(c,0);
1965	        /* If there is no pattern the length is the entire set size, otherwise we defer the reply size */
1966	        if (use_pattern)
1967	            replylen = addReplyDeferredLen(c);
1968	        else {
1969	            array_reply_len = setTypeSize(o);
1970	            addReplyArrayLen(c, array_reply_len);
1971	        }
1972	
1973	        setTypeIterator si;
1974	        unsigned long cur_length = 0;
1975	        setTypeInitIterator(&si, o);
1976	        while (setTypeNext(&si, &str, &len, &llele) != -1) {
1977	            if (str == NULL) {
1978	                len = ll2string(buf, sizeof(buf), llele);
1979	            }
1980	            char *key = str ? str : buf;
1981	            if (use_pattern && !stringmatchlen(pat, patlen, key, len, 0)) {
1982	                continue;
1983	            }
1984	            addReplyBulkCBuffer(c, key, len);
1985	            cur_length++;
1986	        }
1987	        setTypeResetIterator(&si);
1988	        if (use_pattern)
1989	            setDeferredArrayLen(c,replylen,cur_length);
1990	        else
1991	            serverAssert(cur_length == array_reply_len); /* fail on corrupt data */
1992	        return;
1993	    } else if ((o->type == OBJ_HASH || o->type == OBJ_ZSET) &&
1994	               o->encoding == OBJ_ENCODING_LISTPACK)
1995	    {
1996	        unsigned char *p = lpFirst(o->ptr);
1997	        unsigned char *str;
1998	        int64_t len;
1999	        unsigned long array_reply_len = 0;
2000	        unsigned char intbuf[LP_INTBUF_SIZE];

488	    dictCheckRehashingCompleted(d);
489	    return 1;
490	}
