181	/* RESTORE key ttl serialized-value [REPLACE] [ABSTTL] [IDLETIME seconds] [FREQ frequency] */
182	void restoreCommand(client *c) {
183	    long long ttl, lfu_freq = -1, lru_idle = -1, lru_clock = -1;
184	    rio payload;
185	    int j, type, replace = 0, absttl = 0;
186	    robj *obj;
187	
188	    /* Parse additional options */
189	    for (j = 4; j < c->argc; j++) {
190	        int additional = c->argc-j-1;
191	        if (!strcasecmp(c->argv[j]->ptr,"replace")) {
192	            replace = 1;
193	        } else if (!strcasecmp(c->argv[j]->ptr,"absttl")) {
194	            absttl = 1;
195	        } else if (!strcasecmp(c->argv[j]->ptr,"idletime") && additional >= 1 &&
196	                   lfu_freq == -1)
197	        {
198	            if (getLongLongFromObjectOrReply(c,c->argv[j+1],&lru_idle,NULL)
199	                != C_OK) return;
200	            if (lru_idle < 0) {
201	                addReplyError(c,"Invalid IDLETIME value, must be >= 0");
202	                return;
203	            }
204	            lru_clock = LRU_CLOCK();
205	            j++; /* Consume additional arg. */
206	        } else if (!strcasecmp(c->argv[j]->ptr,"freq") && additional >= 1 &&
207	                   lru_idle == -1)
208	        {
209	            if (getLongLongFromObjectOrReply(c,c->argv[j+1],&lfu_freq,NULL)
210	                != C_OK) return;
211	            if (lfu_freq < 0 || lfu_freq > 255) {
212	                addReplyError(c,"Invalid FREQ value, must be >= 0 and <= 255");
213	                return;
214	            }
215	            j++; /* Consume additional arg. */
216	        } else {
217	            addReplyErrorObject(c,shared.syntaxerr);
218	            return;
219	        }
220	    }
221	
222	    /* Make sure this key does not already exist here... */
223	    robj *key = c->argv[1];
224	    kvobj *oldval = lookupKeyWrite(c->db,key);
225	    int oldtype = oldval ? oldval->type : -1;
226	    if (!replace && oldval) {
227	        addReplyErrorObject(c,shared.busykeyerr);
228	        return;
229	    }
230	
231	    /* Check if the TTL value makes sense */
232	    if (getLongLongFromObjectOrReply(c,c->argv[2],&ttl,NULL) != C_OK) {
233	        return;
234	    } else if (ttl < 0) {
235	        addReplyError(c,"Invalid TTL value, must be >= 0");
236	        return;
237	    }
238	
239	    /* Verify RDB version and data checksum. */
240	    if (verifyDumpPayload(c->argv[3]->ptr,sdslen(c->argv[3]->ptr),NULL) == C_ERR)
241	    {
242	        addReplyError(c,"DUMP payload version or checksum are wrong");
243	        return;
244	    }
245	
246	    rioInitWithBuffer(&payload,c->argv[3]->ptr);
247	
248	    /* Initialize metadata spec to collect metadata+expiry from payload. */
249	    KeyMetaSpec keymeta;
250	    keyMetaSpecInit(&keymeta);
251	
252	    /* Compute TTL early so we can add it to metadata spec in correct order */
253	    if (ttl) {
254	        if (!absttl) ttl+=commandTimeSnapshot();
255	        keyMetaSpecAdd(&keymeta, KEY_META_ID_EXPIRE, ttl);
256	    }
257	
258	    /* With metadata, type = RDB_OPCODE_KEY_META. Layout: [<META>,]<TYPE>,<KEY>,<VALUE> */
259	    type = rdbLoadType(&payload);
260	    if (rdbResolveKeyType(&payload, &type, c->db->id, &keymeta) == -1) {
261	        addReplyError(c,"Bad data format");
262	        return;
263	    }
264	
265	    /* Load the object */
266	    if ((obj = rdbLoadObject(type,&payload,key->ptr,c->db->id,NULL)) == NULL)
267	    {
268	        keyMetaSpecCleanup(&keymeta);
269	        addReplyError(c,"Bad data format");
270	        return;
271	    }
272	
273	    /* Remove the old key if needed. */
274	    int deleted = 0;
275	    if (replace)
276	        deleted = dbDelete(c->db,key);
277	
278	    if (ttl && checkAlreadyExpired(ttl)) {
279	        if (deleted) {
280	            robj *aux = server.lazyfree_lazy_server_del ? shared.unlink : shared.del;
281	            rewriteClientCommandVector(c, 2, aux, key);
282	            keyModified(c,c->db,key,NULL,1);
283	            notifyKeyspaceEvent(NOTIFY_GENERIC,"del",key,c->db->id);
284	            server.dirty++;
285	        }
286	        /* Update the stats, see setGenericCommand for details. */
287	        server.stat_expiredkeys++;
288	        keyMetaSpecCleanup(&keymeta);
289	        decrRefCount(obj);
290	        addReply(c, shared.ok);
291	        return;
292	    }
293	
294	    /* Create the key and set the TTL if any */
295	    kvobj *kv = dbAddInternal(c->db, key, &obj, NULL, &keymeta);
296	
297	    /* Save type: kv may be reallocated by module callbacks during notifyKeyspaceEvent below. */
298	    int kvtype = kv->type;
299	
300	    /* If minExpiredField was set, then the object is hash with expiration
301	     * on fields and need to register it in global HFE DS */
302	    if (kvtype == OBJ_HASH) {
303	        uint64_t minExpiredField = hashTypeGetMinExpire(kv, 1);
304	        if (minExpiredField != EB_EXPIRE_TIME_INVALID)
305	            estoreAdd(c->db->subexpires, getKeySlot(key->ptr), kv, minExpiredField);
306	    }
307	
308	    if (kvtype == OBJ_STREAM)
309	        streamKeyLoaded(c->db, key, kv);
310	
311	    if (ttl) {
312	        if (!absttl) {
313	            /* Propagate TTL as absolute timestamp */
314	            robj *ttl_obj = createStringObjectFromLongLong(ttl);
315	            rewriteClientCommandArgument(c,2,ttl_obj);
316	            decrRefCount(ttl_obj);
317	            rewriteClientCommandArgument(c,c->argc,shared.absttl);
318	        }
319	    }
320	    objectSetLRUOrLFU(kv, lfu_freq, lru_idle, lru_clock, 1000);
321	    keyModified(c,c->db,key,NULL,1);
322	    notifyKeyspaceEvent(NOTIFY_GENERIC,"restore",key,c->db->id);
323	    KSN_INVALIDATE_KVOBJ(kv);
324	
325	    /* If we deleted a key that means REPLACE parameter was passed and the
326	     * destination key existed. */
327	    if (deleted) {
328	        notifyKeyspaceEvent(NOTIFY_OVERWRITTEN, "overwritten", key, c->db->id);
329	        if (oldtype != kvtype) {
330	            notifyKeyspaceEvent(NOTIFY_TYPE_CHANGED, "type_changed", key, c->db->id);
331	        }
332	    }
333	    addReply(c,shared.ok);
334	    server.dirty++;
335	}
336	/* MIGRATE socket cache implementation.
337	 *
338	 * We take a map between host:ip and a TCP socket that we used to connect
339	 * to this instance in recent time.
340	 * This sockets are closed when the max number we cache is reached, and also
341	 * in serverCron() when they are around for more than a few seconds. */
342	#define MIGRATE_SOCKET_CACHE_ITEMS 64 /* max num of items in the cache. */
343	#define MIGRATE_SOCKET_CACHE_TTL 10 /* close cached sockets after 10 sec. */
344	
345	typedef struct migrateCachedSocket {
346	    connection *conn;
347	    long last_dbid;
348	    time_t last_use_time;
349	} migrateCachedSocket;
350	
351	/* Return a migrateCachedSocket containing a TCP socket connected with the
352	 * target instance, possibly returning a cached one.
353	 *
354	 * This function is responsible of sending errors to the client if a
355	 * connection can't be established. In this case -1 is returned.
356	 * Otherwise on success the socket is returned, and the caller should not
357	 * attempt to free it after usage.
358	 *
359	 * If the caller detects an error while using the socket, migrateCloseSocket()
360	 * should be called so that the connection will be created from scratch
361	 * the next time. */
362	migrateCachedSocket* migrateGetSocket(client *c, robj *host, robj *port, long timeout) {
363	    connection *conn;
364	    sds name = sdsempty();
365	    migrateCachedSocket *cs;
366	
367	    /* Check if we have an already cached socket for this ip:port pair. */
368	    name = sdscatlen(name,host->ptr,sdslen(host->ptr));
369	    name = sdscatlen(name,":",1);
370	    name = sdscatlen(name,port->ptr,sdslen(port->ptr));
371	    cs = dictFetchValue(server.migrate_cached_sockets,name);
372	    if (cs) {
373	        sdsfree(name);
374	        cs->last_use_time = server.unixtime;
375	        return cs;
376	    }
377	
378	    /* No cached socket, create one. */
379	    if (dictSize(server.migrate_cached_sockets) == MIGRATE_SOCKET_CACHE_ITEMS) {
380	        /* Too many items, drop one at random. */
381	        dictEntry *de = dictGetRandomKey(server.migrate_cached_sockets);
382	        cs = dictGetVal(de);
383	        connClose(cs->conn);
384	        zfree(cs);
385	        dictDelete(server.migrate_cached_sockets,dictGetKey(de));
386	    }
387	
388	    /* Create the connection */
389	    conn = connCreate(server.el, connTypeOfCluster());
390	    if (connBlockingConnect(conn, host->ptr, atoi(port->ptr), timeout)
391	        != C_OK) {
392	        addReplyError(c,"-IOERR error or timeout connecting to the client");
393	        connClose(conn);
394	        sdsfree(name);
395	        return NULL;
396	    }
397	    connEnableTcpNoDelay(conn);
398	
399	    /* Add to the cache and return it to the caller. */
400	    cs = zmalloc(sizeof(*cs));
401	    cs->conn = conn;
402	
403	    cs->last_dbid = -1;
404	    cs->last_use_time = server.unixtime;
405	    dictAdd(server.migrate_cached_sockets,name,cs);
406	    return cs;
407	}
408	
409	/* Free a migrate cached connection. */
410	void migrateCloseSocket(robj *host, robj *port) {
411	    sds name = sdsempty();
412	    migrateCachedSocket *cs;
413	
414	    name = sdscatlen(name,host->ptr,sdslen(host->ptr));
415	    name = sdscatlen(name,":",1);
416	    name = sdscatlen(name,port->ptr,sdslen(port->ptr));
417	    cs = dictFetchValue(server.migrate_cached_sockets,name);
418	    if (!cs) {
419	        sdsfree(name);
420	        return;
421	    }
422	
423	    connClose(cs->conn);
424	    zfree(cs);
425	    dictDelete(server.migrate_cached_sockets,name);
426	    sdsfree(name);
427	}
428	
429	void migrateCloseTimedoutSockets(void) {
430	    dictIterator di;
431	    dictEntry *de;
432	
433	    dictInitSafeIterator(&di, server.migrate_cached_sockets);
434	    while((de = dictNext(&di)) != NULL) {
435	        migrateCachedSocket *cs = dictGetVal(de);
436	
437	        if ((server.unixtime - cs->last_use_time) > MIGRATE_SOCKET_CACHE_TTL) {
438	            connClose(cs->conn);
439	            zfree(cs);
440	            dictDelete(server.migrate_cached_sockets,dictGetKey(de));
441	        }
442	    }
443	    dictResetIterator(&di);
444	}
