127	/* Low level logging. To use only for very big messages, otherwise
128	 * serverLog() is to prefer. */
129	void serverLogRaw(int level, const char *msg) {
130	    const int syslogLevelMap[] = { LOG_DEBUG, LOG_INFO, LOG_NOTICE, LOG_WARNING };
131	    const char *c = ".-*#";
132	    FILE *fp;
133	    char buf[64];
134	    int rawmode = (level & LL_RAW);
135	    int log_to_stdout = server.logfile[0] == '\0';
136	
137	    level &= 0xff; /* clear flags */
138	    if (level < server.verbosity) return;
139	
140	    fp = log_to_stdout ? stdout : fopen(server.logfile,"a");
141	    if (!fp) return;
142	
143	    if (rawmode) {
144	        fprintf(fp,"%s",msg);
145	    } else {
146	        int off;
147	        struct timeval tv;
148	        int role_char;
149	        int daylight_active = 0;
150	        pid_t pid = getpid();
151	
152	        gettimeofday(&tv,NULL);
153	        struct tm tm;
154	        atomicGet(server.daylight_active, daylight_active);
155	        nolocks_localtime(&tm,tv.tv_sec,server.timezone,daylight_active);
156	        off = strftime(buf,sizeof(buf),"%d %b %Y %H:%M:%S.",&tm);
157	        snprintf(buf+off,sizeof(buf)-off,"%03d",(int)tv.tv_usec/1000);
158	        if (server.sentinel_mode) {
159	            role_char = 'X'; /* Sentinel. */
160	        } else if (pid != server.pid) {
161	            role_char = 'C'; /* RDB / AOF writing child. */
162	        } else {
163	            role_char = (server.masterhost ? 'S':'M'); /* Slave or Master. */
164	        }
165	        fprintf(fp,"%d:%c %s %c %s\n",
166	            (int)getpid(),role_char, buf,c[level],msg);
167	    }
168	    fflush(fp);
169	
170	    if (!log_to_stdout) fclose(fp);
171	    if (server.syslog_enabled) syslog(syslogLevelMap[level], "%s", msg);
172	}
