193	    char buf[64];
194	
195	    if ((level&0xff) < server.verbosity || (log_to_stdout && server.daemonize))
196	        return;
197	    fd = log_to_stdout ? STDOUT_FILENO :
198	                         open(server.logfile, O_APPEND|O_CREAT|O_WRONLY, 0644);
199	    if (fd == -1) return;
200	    if (level & LL_RAW) {
201	        if (write(fd,msg,strlen(msg)) == -1) goto err;
202	    }
203	    else {
204	        ll2string(buf,sizeof(buf),getpid());
205	        if (write(fd,buf,strlen(buf)) == -1) goto err;
206	        if (write(fd,":signal-handler (",17) == -1) goto err;
207	        ll2string(buf,sizeof(buf),time(NULL));
208	        if (write(fd,buf,strlen(buf)) == -1) goto err;
209	        if (write(fd,") ",2) == -1) goto err;
210	        if (write(fd,msg,strlen(msg)) == -1) goto err;
211	        if (write(fd,"\n",1) == -1) goto err;
212	    }
213	err:
214	    if (!log_to_stdout) close(fd);
215	}
