217	/* An async-signal-safe version of serverLog. if LL_RAW is not included in level flags,
218	 * The message format is: <pid>:signal-handler (<time>) <msg> \n
219	 * with LL_RAW flag only the msg is printed (with no new line at the end)
220	 *
221	 * We actually use this only for signals that are not fatal from the point
222	 * of view of Redis. Signals that are going to kill the server anyway and
223	 * where we need printf-alike features are served by serverLog(). */
224	void serverLogFromHandler(int level, const char *fmt, ...) {
225	    va_list ap;
226	    char msg[LOG_MAX_LEN];
227	
228	    va_start(ap, fmt);
229	    vsnprintf_async_signal_safe(msg, sizeof(msg), fmt, ap);
230	    va_end(ap);
231	
232	    serverLogRawFromHandler(level, msg);
233	}
