235	/* Return the UNIX time in microseconds */
236	long long ustime(void) {
237	    struct timeval tv;
238	    long long ust;
239	
240	    gettimeofday(&tv, NULL);
241	    ust = ((long long)tv.tv_sec)*1000000;
242	    ust += tv.tv_usec;
243	    return ust;
244	}
