273	/* After an RDB dump or AOF rewrite we exit from children using _exit() instead of
274	 * exit(), because the latter may interact with the same file objects used by
275	 * the parent process. However if we are testing the coverage normal exit() is
276	 * used in order to obtain the right coverage information. 
277	 * There is a caveat for when we exit due to a signal.
278	 * In this case we want the function to be async signal safe, so we can't use exit()
279	 */
280	void exitFromChild(int retcode, int from_signal) {
281	#ifdef COVERAGE_TEST
282	    if (!from_signal) {
283	        exit(retcode);
284	    } else {
285	        _exit(retcode);
286	    }
287	#else
288	    UNUSED(from_signal);
289	    _exit(retcode);
290	#endif
291	}
