354	            /* we don't call kvsUpdateHistogram() because it contains debugServerAssert
355	             * that may fail in bg thread as kvstore might not being fully initialized */
356	            int old_bin = (alloc_size == 0) ? 0 : log2ceil(alloc_size) + 1;
