69	/* 
70	 * Update histogram of keys-sizes
71	 * 
72	 * It is used to track the distribution of key sizes in the dataset. It is updated 
73	 * every time key's length is modified. Available to user via INFO command. 
74	 * 
75	 * The histogram is a base-2 logarithmic histogram, with 60 bins. The i'th bin
76	 * represents the number of keys with a size in the range 2^i and 2^(i+1) 
77	 * exclusive. oldLen/newLen must be smaller than 2^48, and if their value 
78	 * equals -1, it means that the key is being created/deleted, respectively. Each
79	 * data type has its own histogram and it is maintained per database.
80	 *
81	 * Example mapping of key lengths to bins:
82	 *               [1,2)->1 [2,4)->2 [4,8)->3 [8,16)->4 ...
83	 *
84	 * Since strings can be zero length, the histogram also tracks:
85	 *               [0,1)->0
86	 */
87	void kvsUpdateHistogram(keysizesHist kvstoreHist, uint32_t type, int64_t oldLen, int64_t newLen) {
88	    if(unlikely(type >= OBJ_TYPE_BASIC_MAX))
89	        return;
90	
91	    if (oldLen > 0) {
92	        int old_bin = log2ceil(oldLen) + 1;
93	        debugServerAssert(old_bin < MAX_KEYSIZES_BINS);
94	        kvstoreHist[type][old_bin]--;
95	        debugServerAssert(kvstoreHist[type][old_bin] >= 0);
96	    } else {
97	        /* here, oldLen can be either 0 or -1 */
98	        if (oldLen == 0) {
99	            /* Only strings can be empty. Yet, a command flow might temporarily
100	             * dbAdd() empty collection, and only after add elements. */
101	            kvstoreHist[type][0]--;
102	            debugServerAssert(kvstoreHist[type][0] >= 0);
103	        }
104	    }
105	    
106	    if (newLen > 0) {
107	        int new_bin = log2ceil(newLen) + 1;
108	        debugServerAssert(new_bin < MAX_KEYSIZES_BINS);
109	        kvstoreHist[type][new_bin]++;
110	    } else {
111	        /* here, newLen can be either 0 or -1 */
112	        if (newLen == 0) {
113	            /* Only strings can be empty. Yet, a command flow might temporarily
114	             * dbAdd() empty collection, and only after add elements. */
115	            kvstoreHist[type][0]++;
116	        }
117	    }
118	}
119	
120	void updateKeysizesHist(redisDb *db, uint32_t type, int64_t oldLen, int64_t newLen) {
121	    kvstoreMetadata *kvstoreMeta = kvstoreGetMetadata(db->keys);
122	    kvsUpdateHistogram(kvstoreMeta->keysizes_hist, type, oldLen, newLen);
123	}
