125	void updateSlotAllocSize(redisDb *db, int didx, kvobj *kv, int64_t oldsize, int64_t newsize) {
126	    debugServerAssert(server.memory_tracking_enabled);
127	    kvstoreDictMetadata *dictMeta = kvstoreGetDictMeta(db->keys, didx, 0);
128	
129	    /* Early return if nothing changed */
130	    if (oldsize == newsize) return;
131	
132	    if (dictMeta) {
133	        /* Handle -1 as a marker for deletion or type change */
134	        if (oldsize >= 0) {
135	            debugServerAssert((size_t)oldsize <= dictMeta->alloc_size);
136	            dictMeta->alloc_size -= oldsize;
137	        }
138	        if (newsize >= 0) {
139	            dictMeta->alloc_size += newsize;
140	        }
141	    }
142	
143	    /* Update allocation size histogram */
144	    kvstoreMetadata *kvstoreMeta = kvstoreGetMetadata(db->keys);
145	    kvsUpdateHistogram(kvstoreMeta->allocsizes_hist, kv->type, oldsize, newsize);
146	}
