148	static void dbgAssertHist(kvstore *kvs, keysizesHist hist,
149	                          size_t (*fn)(kvobj *), const char *name) {
150	    /* Scan DB and build expected histogram by scanning all keys */
151	    int64_t scanHist[MAX_KEYSIZES_TYPES][MAX_KEYSIZES_BINS] = {{0}};
152	    dictEntry *de;
153	    kvstoreIterator kvs_it;
154	    kvstoreIteratorInit(&kvs_it, kvs);
155	    while ((de = kvstoreIteratorNext(&kvs_it)) != NULL) {
156	        kvobj *kv = dictGetKV(de);
157	        if (kv->type < OBJ_TYPE_BASIC_MAX) {
158	            int64_t len = fn(kv);
159	            scanHist[kv->type][(len == 0) ? 0 : log2ceil(len) + 1]++;
160	        }
161	    }
162	    kvstoreIteratorReset(&kvs_it);
163	    for (int type = 0; type < OBJ_TYPE_BASIC_MAX; type++) {
164	        volatile int64_t *keysizesHist = hist[type];
165	        for (int i = 0; i < MAX_KEYSIZES_BINS; i++) {
166	            if (scanHist[type][i] == keysizesHist[i])
167	                continue;
168	
169	            /* print scanStr vs. expected histograms for debugging */
170	            char scanStr[500] = {0}, keysizesStr[500] = {0};
171	            int l1 = 0, l2 = 0;
172	            for (int j = 0; (j < MAX_KEYSIZES_BINS) && (l1 < 500) && (l2 < 500); j++) {
173	                if (scanHist[type][j])
174	                    l1 += snprintf(scanStr + l1, sizeof(scanStr) - l1,
175	                                        "[%d]=%"PRId64" ", j, scanHist[type][j]);
176	                if (keysizesHist[j])
177	                    l2 += snprintf(keysizesStr + l2, sizeof(keysizesStr) - l2,
178	                                            "[%d]=%"PRId64" ", j, keysizesHist[j]);
179	            }
180	            serverPanic("%s: type=%d\nscanStr=%s\nkeysizes=%s\n",
181	                        name, type, scanStr, keysizesStr);
182	        }
183	    }
184	}
