192	/* Assert per-slot alloc_size (For debugging only) */
193	static void dbgAssertAllocSizePerSlot(redisDb *db) {
194	    if (!server.memory_tracking_enabled) return;
195	    
196	    /* Check allocsizes histogram per db */
197	    kvstoreMetadata *meta = kvstoreGetMetadata(db->keys);
198	    dbgAssertHist(db->keys, meta->allocsizes_hist, kvobjAllocSize, "dbgAssertAllocsizesHist");
199	    
200	    /* Check alloc_size per slot */    
201	    size_t slot_sizes[CLUSTER_SLOTS] = {0};
202	    dictEntry *de;
203	    kvstoreIterator kvs_it;
204	    kvstoreIteratorInit(&kvs_it, db->keys);
205	    while ((de = kvstoreIteratorNext(&kvs_it)) != NULL) {
206	        int slot = kvstoreIteratorGetCurrentDictIndex(&kvs_it);
207	        kvobj *kv = dictGetKV(de);
208	        slot_sizes[slot] += kvobjAllocSize(kv);
209	    }
210	    kvstoreIteratorReset(&kvs_it);
211	
212	    int num_slots = kvstoreNumDicts(db->keys);
213	    for (int slot = 0; slot < num_slots; slot++) {
214	        kvstoreDictMetadata *dictMeta = kvstoreGetDictMeta(db->keys, slot, 0);
215	        size_t want = slot_sizes[slot];
216	        size_t have = dictMeta ? dictMeta->alloc_size : 0;
217	        if (have == want) continue;
218	        serverPanic("dbgAssertAllocSizePerSlot: slot=%d expected=%zu actual=%zu",
219	                    slot, want, have);
220	    }
221	}
