223	/* Run debug assertions based on server.dbg_assert_flags.
224	 *
225	 * DBG_ASSERT_KEYSIZES:   Triggered by DEBUG KEYSIZES-HIST-ASSERT 1
226	 * DBG_ASSERT_ALLOC_SLOT: Triggered by DEBUG ALLOCSIZE-SLOTS-ASSERT 1
227	 */
228	void dbgRunAssertions(redisDb *db) {
229	    /* Don't assert during nested calls. Intermediate state may be inconsistent. */
230	    if (server.execution_nesting) return;
231	
232	    /* Don't assert during RDB loading. Database may be in inconsistent state. */
233	    if (server.loading || server.async_loading) return;
234	
235	    /* Don't assert during ASM background trim or import.
236	     * - During background trim, histogram delta hasn't been applied yet.
237	     * - During import, assertions can introduce slowdown and cause ASM tests to fail. */
238	    if (asmIsBgTrimRunning() || asmImportInProgress()) return;
239	
240	    if (server.dbg_assert_flags & DBG_ASSERT_KEYSIZES)
241	        dbgAssertKeysizesHist(db);
242	
243	    if (server.dbg_assert_flags & DBG_ASSERT_ALLOC_SLOT)
244	        dbgAssertAllocSizePerSlot(db);
245	}
