247	/* Lookup a kvobj for read or write operations, or return NULL if the it is not
248	 * found in the specified DB. This function implements the functionality of
249	 * lookupKeyRead(), lookupKeyWrite() and their ...WithFlags() variants.
250	 *
251	 * link - If key found, return the link of the key.
252	 *        If key not found, return the bucket link, where the key should be added.
253	 *        Or NULL if dict wasn't allocated yet.
254	 *
255	 * Side-effects of calling this function:
256	 *
257	 * 1. A key gets expired if it reached it's TTL.
258	 * 2. The key's last access time is updated.
259	 * 3. The global keys hits/misses stats are updated (reported in INFO).
260	 * 4. If keyspace notifications are enabled, a "keymiss" notification is fired.
261	 *
262	 * Flags change the behavior of this command:
263	 *
264	 *  LOOKUP_NONE (or zero): No special flags are passed.
265	 *  LOOKUP_NOTOUCH: Don't alter the last access time of the key.
266	 *  LOOKUP_NONOTIFY: Don't trigger keyspace event on key miss.
267	 *  LOOKUP_NOSTATS: Don't increment key hits/misses counters.
268	 *  LOOKUP_WRITE: Prepare the key for writing (delete expired keys even on
269	 *                replicas, use separate keyspace stats and events (TODO)).
270	 *  LOOKUP_NOEXPIRE: Perform expiration check, but avoid deleting the key,
271	 *                   so that we don't have to propagate the deletion.
272	 *
273	 * Note: this function also returns NULL if the key is logically expired but
274	 * still existing, in case this is a replica and the LOOKUP_WRITE is not set.
275	 * Even if the key expiry is master-driven, we can correctly report a key is
276	 * expired on replicas even if the master is lagging expiring our key via DELs
277	 * in the replication link. */
278	kvobj *lookupKey(redisDb *db, robj *key, int flags, dictEntryLink *link) {
279	
280	    kvobj *val = dbFindByLink(db, key->ptr, link);
281	
282	    if (val) {
283	        /* Forcing deletion of expired keys on a replica makes the replica
284	         * inconsistent with the master. We forbid it on readonly replicas, but
285	         * we have to allow it on writable replicas to make write commands
286	         * behave consistently.
287	         *
288	         * It's possible that the WRITE flag is set even during a readonly
289	         * command, since the command may trigger events that cause modules to
290	         * perform additional writes. */
291	        int is_ro_replica = server.masterhost && server.repl_slave_ro;
292	        int expire_flags = 0;
293	        if (flags & LOOKUP_WRITE && !is_ro_replica)
294	            expire_flags |= EXPIRE_FORCE_DELETE_EXPIRED;
295	        if (flags & LOOKUP_NOEXPIRE)
296	            expire_flags |= EXPIRE_AVOID_DELETE_EXPIRED;
297	        if (flags & LOOKUP_ACCESS_EXPIRED)
298	            expire_flags |= EXPIRE_ALLOW_ACCESS_EXPIRED;
299	        if (flags & LOOKUP_ACCESS_TRIMMED)
300	            expire_flags |= EXPIRE_ALLOW_ACCESS_TRIMMED;
301	        if (expireIfNeeded(db, key, val, expire_flags) != KEY_VALID) {
302	            /* The key is no longer valid. */
303	            val = NULL;
304	            if (link) *link = NULL;
305	        }
306	    }
307	
308	    if (val) {
309	        /* Update the access time for the ageing algorithm.
310	         * Don't do it if we have a saving child, as this will trigger
311	         * a copy on write madness. */
312	        if (((flags & LOOKUP_NOTOUCH) == 0) &&
313	            (server.current_client && server.current_client->flags & CLIENT_NO_TOUCH) &&
314	            (server.executing_client && server.executing_client->cmd->proc != touchCommand))
315	            flags |= LOOKUP_NOTOUCH;
316	        if (!hasActiveChildProcess() && !(flags & LOOKUP_NOTOUCH)){
317	            if (server.maxmemory_policy & MAXMEMORY_FLAG_LFU) {
318	                updateLFU(val);
319	            } else if (!(server.maxmemory_policy & MAXMEMORY_FLAG_LRM)) {
320	                /* LRM policy should NOT update timestamp on reads. */
321	                val->lru = LRU_CLOCK();
322	            }
323	        }
324	
325	        if (!(flags & (LOOKUP_NOSTATS | LOOKUP_WRITE)))
326	            server.stat_keyspace_hits++;
327	        /* TODO: Use separate hits stats for WRITE */
328	    } else {
329	        if (!(flags & (LOOKUP_NONOTIFY | LOOKUP_WRITE)))
330	            notifyKeyspaceEvent(NOTIFY_KEY_MISS, "keymiss", key, db->id);
331	        if (!(flags & (LOOKUP_NOSTATS | LOOKUP_WRITE)))
332	            server.stat_keyspace_misses++;
333	        /* TODO: Use separate misses stats and notify event for WRITE */
334	    }
335	
336	    return val;
337	}
