395	/* Add a key-value entry to the DB.
396	 *
397	 * A copy of 'key' is stored in the database. The caller must ensure the
398	 * `key` is properly freed by calling decrRefcount(key).
399	 *
400	 * The value may (if its reference counter == 1) be reallocated and become
401	 * invalid after a call to this function. The (possibly reallocated) value is
402	 * stored in the database and the 'valref' pointer is updated to point to the
403	 * new allocation.
404	 *
405	 * The reference counter of the value pointed to by valref is not incremented,
406	 * so the caller should not free the value using decrRefcount after calling this
407	 * function.
408	 *
409	 * link - Optional link to bucket where the key should be added.
410	 *          On return, get updated, by need, to the inserted key.
411	 *          
412	 * keymeta - Defines metadata to be attached to the key. Including optional 
413	 *           expiration and modules metadata to be copied (REQUIRED).
414	 */
415	kvobj *dbAddInternal(redisDb *db, robj *key, robj **valref, dictEntryLink *link, 
416	                     const KeyMetaSpec *keymeta) 
417	{
418	    int slot = getKeySlot(key->ptr);
419	    dictEntryLink tmp = NULL;
420	    if (link == NULL) link = &tmp;
421	    robj *val = *valref;
422	    kvobj *kv = kvobjSet(key->ptr, val, keymeta->metabits);
423	    initObjectLRUOrLFU(kv);
424	    kvstoreDictSetAtLink(db->keys, slot, kv, link, 1);
425	    
426	    /* Handle metadata (expiration and modules metadata) */
427	    if (keymeta->metabits) {
428	        if (keymeta->metabits & KEY_META_MASK_EXPIRE) {
429	            /* Expiry is always the first meta (from last) */
430	            long long expire = keymeta->meta[KEY_META_ID_MAX - 1];
431	            kvobj *newkv = setExpireByLink(NULL, db, key->ptr, expire, *link);
432	            serverAssert(newkv == kv);
433	        }
434	        
435	        /* memcpy modules metadata to beginning of kvobj */
436	        if (keymeta->metabits & KEY_META_MASK_MODULES)
437	            /* Also trivial overwrite expire */
438	            memcpy(kvobjGetAllocPtr(kv), 
439	                   keymeta->meta + KEY_META_ID_MAX - keymeta->numMeta, 
440	                   keymeta->numMeta * sizeof(uint64_t));
441	    }
442	
443	    signalKeyAsReady(db, key, kv->type);
444	    notifyKeyspaceEvent(NOTIFY_NEW,"new",key,db->id);
445	    updateKeysizesHist(db, kv->type, -1, getObjectLength(kv)); /* add hist */
446	    if (server.memory_tracking_enabled)
447	        updateSlotAllocSize(db, slot, kv, -1, kvobjAllocSize(kv));
448	    *valref = kv;
449	    return kv;
450	}
