452	/* Read dbAddInternal() comment */
453	kvobj *dbAdd(redisDb *db, robj *key, robj **valref) {
454	    KeyMetaSpec keyMetaEmpty; /* No metadata added */
455	    keyMetaSpecInit(&keyMetaEmpty);
456	    return dbAddInternal(db, key, valref, NULL, &keyMetaEmpty);
457	}
