465	/* Returns key's hash slot when cluster mode is enabled, or 0 when disabled.
466	 * The only difference between this function and getKeySlot, is that it's not using cached key slot from the current_client
467	 * and always calculates CRC hash.
468	 * This is useful when slot needs to be calculated for a key that user didn't request for, such as in case of eviction. */
469	int calculateKeySlot(sds key) {
470	    return server.cluster_enabled ? keyHashSlot(key, (int) sdslen(key)) : 0;
471	}
472	
473	/* Return slot-specific dictionary for key based on key's hash slot when cluster mode is enabled, else 0.*/
474	int getKeySlot(sds key) {
475	    if (!server.cluster_enabled) return 0;
476	    /* This is performance optimization that uses pre-set slot id from the current command,
477	     * in order to avoid calculation of the key hash.
478	     *
479	     * This optimization is only used when current_client flag `CLIENT_EXECUTING_COMMAND` is set.
480	     * It only gets set during the execution of command under `call` method. Other flows requesting
481	     * the key slot would fallback to calculateKeySlot.
482	     */
483	    if (server.current_client && server.current_client->slot >= 0 && server.current_client->flags & CLIENT_EXECUTING_COMMAND) {
484	        debugServerAssertWithInfo(server.current_client, NULL,
485	                                  (int)keyHashSlot(key, (int)sdslen(key)) == server.current_client->slot);
486	        return server.current_client->slot;
487	    }
488	    int slot = keyHashSlot(key, (int)sdslen(key));
489	    return slot;
490	}
