44	    KEY_VALID = 0, /* Could be volatile and not yet expired, non-volatile, or even non-existing key. */
45	    KEY_EXPIRED, /* Logically expired but not yet deleted. */
46	    KEY_DELETED, /* The key was deleted now. */
