52	/* Update LFU when an object is accessed.
53	 * Firstly, decrement the counter if the decrement time is reached.
54	 * Then logarithmically increment the counter, and update the access time. */
55	void updateLFU(robj *val) {
56	    unsigned long counter = LFUDecrAndReturn(val);
57	    counter = LFULogIncr(counter);
58	    val->lru = (LFUGetTimeInMinutes()<<8) | counter;
59	}
60	
61	/* Update LRM when an object is modified. */
62	void updateLRM(robj *o) {
63	    if (o->refcount == OBJ_SHARED_REFCOUNT)
64	        return;
65	    if (server.maxmemory_policy & MAXMEMORY_FLAG_LRM) {
66	        o->lru = LRU_CLOCK();
67	    }
68	}
