70	/* 
71	 * Update histogram of keys-sizes
72	 * 
73	 * It is used to track the distribution of key sizes in the dataset. It is updated 
74	 * every time key's length is modified. Available to user via INFO command. 
75	 * 
76	 * The histogram is a base-2 logarithmic histogram, with 60 bins. The i'th bin
77	 * represents the number of keys with a size in the range 2^i and 2^(i+1) 
78	 * exclusive. oldLen/newLen must be smaller than 2^48, and if their value 
79	 * equals -1, it means that the key is being created/deleted, respectively. Each
80	 * data type has its own histogram and it is maintained per database.
81	 *
82	 * Example mapping of key lengths to bins:
83	 *               [1,2)->1 [2,4)->2 [4,8)->3 [8,16)->4 ...
84	 *
85	 * Since strings can be zero length, the histogram also tracks:
86	 *               [0,1)->0
87	 */
88	void kvsUpdateHistogram(keysizesHist kvstoreHist, uint32_t type, int64_t oldLen, int64_t newLen) {
89	    if(unlikely(type >= OBJ_TYPE_BASIC_MAX))
90	        return;
91	
92	    if (oldLen > 0) {
93	        int old_bin = log2ceil(oldLen) + 1;
94	        debugServerAssert(old_bin < MAX_KEYSIZES_BINS);
95	        kvstoreHist[type][old_bin]--;
96	        debugServerAssert(kvstoreHist[type][old_bin] >= 0);
97	    } else {
98	        /* here, oldLen can be either 0 or -1 */
99	        if (oldLen == 0) {
100	            /* Only strings can be empty. Yet, a command flow might temporarily
101	             * dbAdd() empty collection, and only after add elements. */
102	            kvstoreHist[type][0]--;
103	            debugServerAssert(kvstoreHist[type][0] >= 0);
104	        }
105	    }
106	    
107	    if (newLen > 0) {
108	        int new_bin = log2ceil(newLen) + 1;
109	        debugServerAssert(new_bin < MAX_KEYSIZES_BINS);
110	        kvstoreHist[type][new_bin]++;
111	    } else {
112	        /* here, newLen can be either 0 or -1 */
113	        if (newLen == 0) {
114	            /* Only strings can be empty. Yet, a command flow might temporarily
115	             * dbAdd() empty collection, and only after add elements. */
116	            kvstoreHist[type][0]++;
117	        }
118	    }
119	}
120	
121	void updateKeysizesHist(redisDb *db, uint32_t type, int64_t oldLen, int64_t newLen) {
122	    kvstoreMetadata *kvstoreMeta = kvstoreGetMetadata(db->keys);
123	    kvsUpdateHistogram(kvstoreMeta->keysizes_hist, type, oldLen, newLen);
124	}
125	
126	void updateSlotAllocSize(redisDb *db, int didx, kvobj *kv, int64_t oldsize, int64_t newsize) {
127	    debugServerAssert(server.memory_tracking_enabled);
128	    kvstoreDictMetadata *dictMeta = kvstoreGetDictMeta(db->keys, didx, 0);
129	
130	    /* Early return if nothing changed */
131	    if (oldsize == newsize) return;
132	
133	    if (dictMeta) {
134	        /* Handle -1 as a marker for deletion or type change */
135	        if (oldsize >= 0) {
136	            debugServerAssert((size_t)oldsize <= dictMeta->alloc_size);
137	            dictMeta->alloc_size -= oldsize;
138	        }
139	        if (newsize >= 0) {
140	            dictMeta->alloc_size += newsize;
141	        }
142	    }
143	
144	    /* Update allocation size histogram */
145	    kvstoreMetadata *kvstoreMeta = kvstoreGetMetadata(db->keys);
146	    kvsUpdateHistogram(kvstoreMeta->allocsizes_hist, kv->type, oldsize, newsize);
147	}
