187	/* Assert keysizes histogram (For debugging only) */
188	static void dbgAssertKeysizesHist(redisDb *db) {
189	    kvstoreMetadata *meta = kvstoreGetMetadata(db->keys);
190	    dbgAssertHist(db->keys, meta->keysizes_hist, getObjectLength, "dbgAssertKeysizesHist");
191	}
