396	/* Add a key-value entry to the DB.
397	 *
398	 * A copy of 'key' is stored in the database. The caller must ensure the
399	 * `key` is properly freed by calling decrRefcount(key).
400	 *
401	 * The value may (if its reference counter == 1) be reallocated and become
402	 * invalid after a call to this function. The (possibly reallocated) value is
403	 * stored in the database and the 'valref' pointer is updated to point to the
404	 * new allocation.
405	 *
406	 * The reference counter of the value pointed to by valref is not incremented,
407	 * so the caller should not free the value using decrRefcount after calling this
408	 * function.
409	 *
410	 * link - Optional link to bucket where the key should be added.
411	 *          On return, get updated, by need, to the inserted key.
412	 *          
413	 * keymeta - Defines metadata to be attached to the key. Including optional 
414	 *           expiration and modules metadata to be copied (REQUIRED).
415	 */
416	kvobj *dbAddInternal(redisDb *db, robj *key, robj **valref, dictEntryLink *link, 
417	                     const KeyMetaSpec *keymeta) 
418	{
419	    int slot = getKeySlot(key->ptr);
420	    dictEntryLink tmp = NULL;
421	    if (link == NULL) link = &tmp;
422	    robj *val = *valref;
423	    kvobj *kv = kvobjSet(key->ptr, val, keymeta->metabits);
424	    initObjectLRUOrLFU(kv);
425	    kvstoreDictSetAtLink(db->keys, slot, kv, link, 1);
426	    
427	    /* Handle metadata (expiration and modules metadata) */
428	    if (keymeta->metabits) {
429	        if (keymeta->metabits & KEY_META_MASK_EXPIRE) {
430	            /* Expiry is always the first meta (from last) */
431	            long long expire = keymeta->meta[KEY_META_ID_MAX - 1];
432	            kvobj *newkv = setExpireByLink(NULL, db, key->ptr, expire, *link);
433	            serverAssert(newkv == kv);
434	        }
435	        
436	        /* memcpy modules metadata to beginning of kvobj */
437	        if (keymeta->metabits & KEY_META_MASK_MODULES)
438	            /* Also trivial overwrite expire */
439	            memcpy(kvobjGetAllocPtr(kv), 
440	                   keymeta->meta + KEY_META_ID_MAX - keymeta->numMeta, 
441	                   keymeta->numMeta * sizeof(uint64_t));
442	    }
443	
444	    signalKeyAsReady(db, key, kv->type);
445	    notifyKeyspaceEvent(NOTIFY_NEW,"new",key,db->id);
446	    updateKeysizesHist(db, kv->type, -1, getObjectLength(kv)); /* add hist */
447	    if (server.memory_tracking_enabled)
448	        updateSlotAllocSize(db, slot, kv, -1, kvobjAllocSize(kv));
449	    *valref = kv;
450	    return kv;
451	}
