804	/* Return a random key, in form of a Redis object.
805	 * If there are no keys, NULL is returned.
806	 *
807	 * The function makes sure to return keys not already expired. */
808	robj *dbRandomKey(redisDb *db) {
809	    dictEntry *de;
810	    int maxtries = 100;
811	    int allvolatile = kvstoreSize(db->keys) == kvstoreSize(db->expires);
812	
813	    while(1) {
814	        robj *keyobj;
815	        int randomSlot = kvstoreGetFairRandomDictIndex(db->keys, accessKeysShouldSkipDictIndex, 16, 1);
816	        if (randomSlot == -1) return NULL;
817	        de = kvstoreDictGetFairRandomKey(db->keys, randomSlot);
818	        if (de == NULL) return NULL;
819	
820	        kvobj *kv = dictGetKV(de);
821	        sds key = kvobjGetKey(kv);
822	        keyobj = createStringObject(key,sdslen(key));
823	        if (allvolatile && (server.masterhost || isPausedActions(PAUSE_ACTION_EXPIRE)) && --maxtries == 0) {
824	            /* If the DB is composed only of keys with an expire set,
825	             * it could happen that all the keys are already logically
826	             * expired in the slave, so the function cannot stop because
827	             * expireIfNeeded() is false, nor it can stop because
828	             * dictGetFairRandomKey() returns NULL (there are keys to return).
829	             * To prevent the infinite loop we do some tries, but if there
830	             * are the conditions for an infinite loop, eventually we
831	             * return a key name that may be already expired. */
832	            return keyobj;
833	        }
834	        if (expireIfNeeded(db, keyobj, kv, 0) != KEY_VALID) {
835	            decrRefCount(keyobj);
836	            continue; /* search for another key. This expired. */
837	        }
838	
839	        return keyobj;
840	    }
841	}
