1583	void keysCommand(client *c) {
1584	    dictEntry *de;
1585	    sds pattern = c->argv[1]->ptr;
1586	    int plen = sdslen(pattern), allkeys, pslot = -1;
1587	    unsigned long numkeys = 0;
1588	    void *replylen = addReplyDeferredLen(c);
1589	    allkeys = (pattern[0] == '*' && plen == 1);
1590	    if (server.cluster_enabled && !allkeys) {
1591	        pslot = patternHashSlot(pattern, plen);
1592	    }
1593	    int has_slot = pslot != -1;
1594	    union {
1595	        kvstoreDictIterator kvs_di;
1596	        kvstoreIterator kvs_it;
1597	    } it;
1598	    if (has_slot) {
1599	        if (!kvstoreDictSize(c->db->keys, pslot) || accessKeysShouldSkipDictIndex(pslot)) {
1600	            /* Requested slot is empty */
1601	            setDeferredArrayLen(c,replylen,0);
1602	            return;
1603	        }
1604	        kvstoreInitDictSafeIterator(&it.kvs_di, c->db->keys, pslot);
1605	    } else {
1606	        kvstoreIteratorInit(&it.kvs_it, c->db->keys);
1607	    }
1608	
1609	    while ((de = has_slot ? kvstoreDictIteratorNext(&it.kvs_di) : kvstoreIteratorNext(&it.kvs_it)) != NULL) {
1610	        if (!has_slot && accessKeysShouldSkipDictIndex(kvstoreIteratorGetCurrentDictIndex(&it.kvs_it))) {
1611	            continue;
1612	        }
1613	
1614	        kvobj *kv = dictGetKV(de);
1615	        sds key = kvobjGetKey(kv);
1616	
1617	        if (allkeys || stringmatchlen(pattern,plen,key,sdslen(key),0)) {
1618	            if (!keyIsExpired(c->db, NULL, kv)) {
1619	                addReplyBulkCBuffer(c, key, sdslen(key));
1620	                numkeys++;
1621	            }
1622	        }
1623	        if (c->flags & CLIENT_CLOSE_ASAP)
1624	            break;
1625	    }
1626	    if (has_slot)
1627	        kvstoreResetDictIterator(&it.kvs_di);
1628	    else
1629	        kvstoreIteratorReset(&it.kvs_it);
1630	    setDeferredArrayLen(c,replylen,numkeys);
1631	}
