1633	/* Data used by the dict scan callback. */
1634	typedef struct {
1635	    vec *keys;    /* elements collected from dict */
1636	    robj *o;      /* o must be a hash/set/zset object, NULL means current db */
1637	    long long type; /* the particular type when scan the db */
1638	    sds pattern;  /* pattern string, NULL means no pattern */
1639	    long sampled; /* cumulative number of keys sampled */
1640	    int no_values; /* set to 1 means to return keys only */
1641	    sds typename; /* typename string, NULL means no type filter */
1642	    redisDb *db;  /* database reference for expiration checks */
1643	} scanData;
