2072	/* Returns 1 if v is a power of two, 0 otherwise. */
2073	static inline int isPowerOfTwo(uint64_t v) {
2074	    return v && !(v & (v - 1));
2075	}
2076	
2077	/* Returns 1 if the command info is valid and 0 otherwise. */
2078	static int moduleValidateCommandInfo(const RedisModuleCommandInfo *info) {
2079	    const RedisModuleCommandInfoVersion *version = info->version;
2080	    if (!version) {
2081	        serverLog(LL_WARNING, "Invalid command info: version missing");
2082	        return 0;
2083	    }
2084	
2085	    /* No validation for the fields summary, complexity, since, tips (strings or
2086	     * NULL) and arity (any integer). */
2087	
2088	    /* History: If since is set, changes must also be set. */
2089	    if (info->history) {
2090	        for (size_t j = 0;
2091	             moduleCmdHistoryEntryAt(version, info->history, j)->since;
2092	             j++)
2093	        {
2094	            if (!moduleCmdHistoryEntryAt(version, info->history, j)->changes) {
2095	                serverLog(LL_WARNING, "Invalid command info: history[%zd].changes missing", j);
2096	                return 0;
2097	            }
2098	        }
2099	    }
2100	
2101	    /* Key specs. */
2102	    if (info->key_specs) {
2103	        for (size_t j = 0;
2104	             moduleCmdKeySpecAt(version, info->key_specs, j)->begin_search_type;
2105	             j++)
2106	        {
2107	            RedisModuleCommandKeySpec *spec =
2108	                moduleCmdKeySpecAt(version, info->key_specs, j);
2109	            if (j >= INT_MAX) {
2110	                serverLog(LL_WARNING, "Invalid command info: Too many key specs");
2111	                return 0; /* redisCommand.key_specs_num is an int. */
2112	            }
2113	
2114	            /* Flags. Exactly one flag in a group is set if and only if the
2115	             * masked bits is a power of two. */
2116	            uint64_t key_flags =
2117	                REDISMODULE_CMD_KEY_RO | REDISMODULE_CMD_KEY_RW |
2118	                REDISMODULE_CMD_KEY_OW | REDISMODULE_CMD_KEY_RM;
2119	            uint64_t write_flags =
2120	                REDISMODULE_CMD_KEY_INSERT | REDISMODULE_CMD_KEY_DELETE |
2121	                REDISMODULE_CMD_KEY_UPDATE;
2122	            if (!isPowerOfTwo(spec->flags & key_flags)) {
2123	                serverLog(LL_WARNING,
2124	                          "Invalid command info: key_specs[%zd].flags: "
2125	                          "Exactly one of the flags RO, RW, OW, RM required", j);
2126	                return 0;
2127	            }
2128	            if ((spec->flags & write_flags) != 0 &&
2129	                !isPowerOfTwo(spec->flags & write_flags))
2130	            {
2131	                serverLog(LL_WARNING,
2132	                          "Invalid command info: key_specs[%zd].flags: "
2133	                          "INSERT, DELETE and UPDATE are mutually exclusive", j);
2134	                return 0;
2135	            }
2136	
2137	            switch (spec->begin_search_type) {
2138	            case REDISMODULE_KSPEC_BS_UNKNOWN: break;
2139	            case REDISMODULE_KSPEC_BS_INDEX: break;
2140	            case REDISMODULE_KSPEC_BS_KEYWORD:
2141	                if (spec->bs.keyword.keyword == NULL) {
2142	                    serverLog(LL_WARNING,
2143	                              "Invalid command info: key_specs[%zd].bs.keyword.keyword "
2144	                              "required when begin_search_type is KEYWORD", j);
2145	                    return 0;
2146	                }
2147	                break;
2148	            default:
2149	                serverLog(LL_WARNING,
2150	                          "Invalid command info: key_specs[%zd].begin_search_type: "
2151	                          "Invalid value %d", j, spec->begin_search_type);
2152	                return 0;
2153	            }
2154	
2155	            /* Validate find_keys_type. */
2156	            switch (spec->find_keys_type) {
2157	            case REDISMODULE_KSPEC_FK_OMITTED: break; /* short for RANGE {0,1,0} */
2158	            case REDISMODULE_KSPEC_FK_UNKNOWN: break;
2159	            case REDISMODULE_KSPEC_FK_RANGE: break;
2160	            case REDISMODULE_KSPEC_FK_KEYNUM: break;
2161	            default:
2162	                serverLog(LL_WARNING,
2163	                          "Invalid command info: key_specs[%zd].find_keys_type: "
2164	                          "Invalid value %d", j, spec->find_keys_type);
2165	                return 0;
2166	            }
2167	        }
2168	    }
2169	
2170	    /* Args, subargs (recursive) */
2171	    return moduleValidateCommandArgs(info->args, version);
2172	}
