2174	/* When from_api is true, converts from REDISMODULE_CMD_KEY_* flags to CMD_KEY_* flags.
2175	 * When from_api is false, converts from CMD_KEY_* flags to REDISMODULE_CMD_KEY_* flags. */
2176	static int64_t moduleConvertKeySpecsFlags(int64_t flags, int from_api) {
2177	    int64_t out = 0;
2178	    int64_t map[][2] = {
2179	        {REDISMODULE_CMD_KEY_RO, CMD_KEY_RO},
2180	        {REDISMODULE_CMD_KEY_RW, CMD_KEY_RW},
2181	        {REDISMODULE_CMD_KEY_OW, CMD_KEY_OW},
2182	        {REDISMODULE_CMD_KEY_RM, CMD_KEY_RM},
2183	        {REDISMODULE_CMD_KEY_ACCESS, CMD_KEY_ACCESS},
2184	        {REDISMODULE_CMD_KEY_INSERT, CMD_KEY_INSERT},
2185	        {REDISMODULE_CMD_KEY_UPDATE, CMD_KEY_UPDATE},
2186	        {REDISMODULE_CMD_KEY_DELETE, CMD_KEY_DELETE},
2187	        {REDISMODULE_CMD_KEY_NOT_KEY, CMD_KEY_NOT_KEY},
2188	        {REDISMODULE_CMD_KEY_INCOMPLETE, CMD_KEY_INCOMPLETE},
2189	        {REDISMODULE_CMD_KEY_VARIABLE_FLAGS, CMD_KEY_VARIABLE_FLAGS},
2190	        {0,0}};
2191	
2192	    int from_idx = from_api ? 0 : 1, to_idx = !from_idx;
2193	    for (int i=0; map[i][0]; i++)
2194	        if (flags & map[i][from_idx]) out |= map[i][to_idx];
2195	    return out;
2196	}
