2198	/* Validates an array of RedisModuleCommandArg. Returns 1 if it's valid and 0 if
2199	 * it's invalid. */
2200	static int moduleValidateCommandArgs(RedisModuleCommandArg *args,
2201	                                     const RedisModuleCommandInfoVersion *version) {
2202	    if (args == NULL) return 1; /* Missing args is OK. */
2203	    for (size_t j = 0; moduleCmdArgAt(version, args, j)->name != NULL; j++) {
2204	        RedisModuleCommandArg *arg = moduleCmdArgAt(version, args, j);
2205	        int arg_type_error = 0;
2206	        moduleConvertArgType(arg->type, &arg_type_error);
2207	        if (arg_type_error) {
2208	            serverLog(LL_WARNING,
2209	                      "Invalid command info: Argument \"%s\": Undefined type %d",
2210	                      arg->name, arg->type);
2211	            return 0;
2212	        }
2213	        if (arg->type == REDISMODULE_ARG_TYPE_PURE_TOKEN && !arg->token) {
2214	            serverLog(LL_WARNING,
2215	                      "Invalid command info: Argument \"%s\": "
2216	                      "token required when type is PURE_TOKEN", args[j].name);
2217	            return 0;
2218	        }
2219	
2220	        if (arg->type == REDISMODULE_ARG_TYPE_KEY) {
2221	            if (arg->key_spec_index < 0) {
2222	                serverLog(LL_WARNING,
2223	                          "Invalid command info: Argument \"%s\": "
2224	                          "key_spec_index required when type is KEY",
2225	                          arg->name);
2226	                return 0;
2227	            }
2228	        } else if (arg->key_spec_index != -1 && arg->key_spec_index != 0) {
2229	            /* 0 is allowed for convenience, to allow it to be omitted in
2230	             * compound struct literals on the form `.field = value`. */
2231	            serverLog(LL_WARNING,
2232	                      "Invalid command info: Argument \"%s\": "
2233	                      "key_spec_index specified but type isn't KEY",
2234	                      arg->name);
2235	            return 0;
2236	        }
2237	
2238	        if (arg->flags & ~(_REDISMODULE_CMD_ARG_NEXT - 1)) {
2239	            serverLog(LL_WARNING,
2240	                      "Invalid command info: Argument \"%s\": Invalid flags",
2241	                      arg->name);
2242	            return 0;
2243	        }
2244	
2245	        if (arg->type == REDISMODULE_ARG_TYPE_ONEOF ||
2246	            arg->type == REDISMODULE_ARG_TYPE_BLOCK)
2247	        {
2248	            if (arg->subargs == NULL) {
2249	                serverLog(LL_WARNING,
2250	                          "Invalid command info: Argument \"%s\": "
2251	                          "subargs required when type is ONEOF or BLOCK",
2252	                          arg->name);
2253	                return 0;
2254	            }
2255	            if (!moduleValidateCommandArgs(arg->subargs, version)) return 0;
2256	        } else {
2257	            if (arg->subargs != NULL) {
2258	                serverLog(LL_WARNING,
2259	                          "Invalid command info: Argument \"%s\": "
2260	                          "subargs specified but type isn't ONEOF nor BLOCK",
2261	                          arg->name);
2262	                return 0;
2263	            }
2264	        }
2265	    }
2266	    return 1;
2267	}
