2269	/* Converts an array of RedisModuleCommandArg into a freshly allocated array of
2270	 * struct redisCommandArg. */
2271	static struct redisCommandArg *moduleCopyCommandArgs(RedisModuleCommandArg *args,
2272	                                                     const RedisModuleCommandInfoVersion *version) {
2273	    size_t count = 0;
2274	    while (moduleCmdArgAt(version, args, count)->name) count++;
2275	    serverAssert(count < SIZE_MAX / sizeof(struct redisCommandArg));
2276	    struct redisCommandArg *realargs = zcalloc((count+1) * sizeof(redisCommandArg));
2277	
2278	    for (size_t j = 0; j < count; j++) {
2279	        RedisModuleCommandArg *arg = moduleCmdArgAt(version, args, j);
2280	        realargs[j].name = zstrdup(arg->name);
2281	        realargs[j].type = moduleConvertArgType(arg->type, NULL);
2282	        if (arg->type == REDISMODULE_ARG_TYPE_KEY)
2283	            realargs[j].key_spec_index = arg->key_spec_index;
2284	        else
2285	            realargs[j].key_spec_index = -1;
2286	        if (arg->token) realargs[j].token = zstrdup(arg->token);
2287	        if (arg->summary) realargs[j].summary = zstrdup(arg->summary);
2288	        if (arg->since) realargs[j].since = zstrdup(arg->since);
2289	        if (arg->deprecated_since) realargs[j].deprecated_since = zstrdup(arg->deprecated_since);
2290	        if (arg->display_text) realargs[j].display_text = zstrdup(arg->display_text);
2291	        realargs[j].flags = moduleConvertArgFlags(arg->flags);
2292	        if (arg->subargs) realargs[j].subargs = moduleCopyCommandArgs(arg->subargs, version);
2293	    }
2294	    return realargs;
2295	}
