2297	static redisCommandArgType moduleConvertArgType(RedisModuleCommandArgType type, int *error) {
2298	    if (error) *error = 0;
2299	    switch (type) {
2300	    case REDISMODULE_ARG_TYPE_STRING: return ARG_TYPE_STRING;
2301	    case REDISMODULE_ARG_TYPE_INTEGER: return ARG_TYPE_INTEGER;
2302	    case REDISMODULE_ARG_TYPE_DOUBLE: return ARG_TYPE_DOUBLE;
2303	    case REDISMODULE_ARG_TYPE_KEY: return ARG_TYPE_KEY;
2304	    case REDISMODULE_ARG_TYPE_PATTERN: return ARG_TYPE_PATTERN;
2305	    case REDISMODULE_ARG_TYPE_UNIX_TIME: return ARG_TYPE_UNIX_TIME;
2306	    case REDISMODULE_ARG_TYPE_PURE_TOKEN: return ARG_TYPE_PURE_TOKEN;
2307	    case REDISMODULE_ARG_TYPE_ONEOF: return ARG_TYPE_ONEOF;
2308	    case REDISMODULE_ARG_TYPE_BLOCK: return ARG_TYPE_BLOCK;
2309	    default:
2310	        if (error) *error = 1;
2311	        return -1;
2312	    }
2313	}
