2455	/* This API allows modules to let Redis process background tasks, and some
2456	 * commands during long blocking execution of a module command.
2457	 * The module can call this API periodically.
2458	 * The flags is a bit mask of these:
2459	 *
2460	 * - `REDISMODULE_YIELD_FLAG_NONE`: No special flags, can perform some background
2461	 *                                  operations, but not process client commands.
2462	 * - `REDISMODULE_YIELD_FLAG_CLIENTS`: Redis can also process client commands.
2463	 *
2464	 * The `busy_reply` argument is optional, and can be used to control the verbose
2465	 * error string after the `-BUSY` error code.
2466	 *
2467	 * When the `REDISMODULE_YIELD_FLAG_CLIENTS` is used, Redis will only start
2468	 * processing client commands after the time defined by the
2469	 * `busy-reply-threshold` config, in which case Redis will start rejecting most
2470	 * commands with `-BUSY` error, but allow the ones marked with the `allow-busy`
2471	 * flag to be executed.
2472	 * This API can also be used in thread safe context (while locked), and during
2473	 * loading (in the `rdb_load` callback, in which case it'll reject commands with
2474	 * the -LOADING error)
2475	 */
2476	void RM_Yield(RedisModuleCtx *ctx, int flags, const char *busy_reply) {
2477	    static int yield_nesting = 0;
2478	    /* Avoid nested calls to RM_Yield */
2479	    if (yield_nesting)
2480	        return;
2481	    yield_nesting++;
2482	
2483	    long long now = getMonotonicUs();
2484	    if (now >= ctx->next_yield_time) {
2485	        /* In loading mode, there's no need to handle busy_module_yield_reply,
2486	         * and busy_module_yield_flags, since redis is anyway rejecting all
2487	         * commands with -LOADING. */
2488	        if (server.loading) {
2489	            /* Let redis process events */
2490	            processEventsWhileBlocked();
2491	        } else {
2492	            const char *prev_busy_module_yield_reply = server.busy_module_yield_reply;
2493	            server.busy_module_yield_reply = busy_reply;
2494	            /* start the blocking operation if not already started. */
2495	            if (!server.busy_module_yield_flags) {
2496	                server.busy_module_yield_flags = BUSY_MODULE_YIELD_EVENTS;
2497	                blockingOperationStarts();
2498	                if (server.current_client)
2499	                    protectClient(server.current_client);

2500	            }
2501	            if (flags & REDISMODULE_YIELD_FLAG_CLIENTS)
2502	                server.busy_module_yield_flags |= BUSY_MODULE_YIELD_CLIENTS;
2503	
2504	            /* Let redis process events */
2505	            if (!pthread_equal(server.main_thread_id, pthread_self())) {
2506	                /* If we are not in the main thread, we defer event loop processing to the main thread
2507	                 * after the main thread enters acquiring GIL state in order to protect the event
2508	                 * loop (ae.c) and avoid potential race conditions. */
2509	
2510	                int acquiring;
2511	                atomicGet(server.module_gil_acquring, acquiring);
2512	                if (!acquiring) {
2513	                    /* If the main thread has not yet entered the acquiring GIL state,
2514	                     * we attempt to wake it up and exit without waiting for it to
2515	                     * acquire the GIL. This avoids blocking the caller, allowing them to
2516	                     * continue with unfinished tasks before the next yield.
2517	                     * We assume the caller keeps the GIL locked. */
2518	                    if (write(server.module_pipe[1],"A",1) != 1) {
2519	                        /* Ignore the error, this is best-effort. */
2520	                    }
2521	                } else {
2522	                    /* Release the GIL, yielding CPU to give the main thread an opportunity to start
2523	                     * event processing, and then acquire the GIL again until the main thread releases it. */
2524	                    moduleReleaseGIL();
2525	                    usleep(0);
2526	                    moduleAcquireGIL();
2527	                }
2528	            } else {
2529	                /* If we are in the main thread, we can safely process events. */
2530	                processEventsWhileBlocked();
2531	            }
2532	
2533	            server.busy_module_yield_reply = prev_busy_module_yield_reply;
2534	            /* Possibly restore the previous flags in case of two nested contexts
2535	             * that use this API with different flags, but keep the first bit
2536	             * (PROCESS_EVENTS) set, so we know to call blockingOperationEnds on time. */
2537	            server.busy_module_yield_flags &= ~BUSY_MODULE_YIELD_CLIENTS;
2538	        }
2539	
2540	        /* decide when the next event should fire. */
2541	        ctx->next_yield_time = now + 1000000 / server.hz;
2542	    }
2543	    yield_nesting--;
2544	}
