2586	/* --------------------------------------------------------------------------
2587	 * ## Automatic memory management for modules
2588	 * -------------------------------------------------------------------------- */
2589	
2590	/* Enable automatic memory management.
2591	 *
2592	 * The function must be called as the first function of a command implementation
2593	 * that wants to use automatic memory.
2594	 *
2595	 * When enabled, automatic memory management tracks and automatically frees
2596	 * keys, call replies and Redis string objects once the command returns. In most
2597	 * cases this eliminates the need of calling the following functions:
2598	 *
2599	 * 1. RedisModule_CloseKey()
2600	 * 2. RedisModule_FreeCallReply()
2601	 * 3. RedisModule_FreeString()
2602	 *
2603	 * These functions can still be used with automatic memory management enabled,
2604	 * to optimize loops that make numerous allocations for example. */
2605	void RM_AutoMemory(RedisModuleCtx *ctx) {
2606	    ctx->flags |= REDISMODULE_CTX_AUTO_MEMORY;
2607	}
2608	
2609	/* Add a new object to release automatically when the callback returns. */
2610	void autoMemoryAdd(RedisModuleCtx *ctx, int type, void *ptr) {
2611	    if (!(ctx->flags & REDISMODULE_CTX_AUTO_MEMORY)) return;
2612	    if (ctx->amqueue_used == ctx->amqueue_len) {
2613	        ctx->amqueue_len *= 2;
2614	        if (ctx->amqueue_len < 16) ctx->amqueue_len = 16;
2615	        ctx->amqueue = zrealloc(ctx->amqueue,sizeof(struct AutoMemEntry)*ctx->amqueue_len);
2616	    }
2617	    ctx->amqueue[ctx->amqueue_used].type = type;
2618	    ctx->amqueue[ctx->amqueue_used].ptr = ptr;
2619	    ctx->amqueue_used++;
2620	}
2621	
2622	/* Mark an object as freed in the auto release queue, so that users can still
2623	 * free things manually if they want.
2624	 *
2625	 * The function returns 1 if the object was actually found in the auto memory
2626	 * pool, otherwise 0 is returned. */
2627	int autoMemoryFreed(RedisModuleCtx *ctx, int type, void *ptr) {
2628	    if (!(ctx->flags & REDISMODULE_CTX_AUTO_MEMORY)) return 0;
2629	
2630	    int count = (ctx->amqueue_used+1)/2;
2631	    for (int j = 0; j < count; j++) {
2632	        for (int side = 0; side < 2; side++) {
2633	            /* For side = 0 check right side of the array, for
2634	             * side = 1 check the left side instead (zig-zag scanning). */
2635	            int i = (side == 0) ? (ctx->amqueue_used - 1 - j) : j;
2636	            if (ctx->amqueue[i].type == type &&
2637	                ctx->amqueue[i].ptr == ptr)
2638	            {
2639	                ctx->amqueue[i].type = REDISMODULE_AM_FREED;
2640	
2641	                /* Switch the freed element and the last element, to avoid growing
2642	                 * the queue unnecessarily if we allocate/free in a loop */
2643	                if (i != ctx->amqueue_used-1) {
2644	                    ctx->amqueue[i] = ctx->amqueue[ctx->amqueue_used-1];
2645	                }
2646	
2647	                /* Reduce the size of the queue because we either moved the top
2648	                 * element elsewhere or freed it */
2649	                ctx->amqueue_used--;
2650	                return 1;
2651	            }
2652	        }
2653	    }
2654	    return 0;
2655	}
2656	
2657	/* Release all the objects in queue. */
2658	void autoMemoryCollect(RedisModuleCtx *ctx) {
2659	    if (!(ctx->flags & REDISMODULE_CTX_AUTO_MEMORY)) return;
2660	    /* Clear the AUTO_MEMORY flag from the context, otherwise the functions
2661	     * we call to free the resources, will try to scan the auto release
2662	     * queue to mark the entries as freed. */
2663	    ctx->flags &= ~REDISMODULE_CTX_AUTO_MEMORY;
2664	    int j;
2665	    for (j = 0; j < ctx->amqueue_used; j++) {
2666	        void *ptr = ctx->amqueue[j].ptr;
2667	        switch(ctx->amqueue[j].type) {
2668	        case REDISMODULE_AM_STRING: decrRefCount(ptr); break;
2669	        case REDISMODULE_AM_REPLY: RM_FreeCallReply(ptr); break;
2670	        case REDISMODULE_AM_KEY: RM_CloseKey(ptr); break;
2671	        case REDISMODULE_AM_DICT: RM_FreeDict(NULL,ptr); break;
2672	        case REDISMODULE_AM_INFO: RM_FreeServerInfo(NULL,ptr); break;
2673	        case REDISMODULE_AM_CONFIG: RM_ConfigIteratorRelease(NULL, ptr); break;
2674	        case REDISMODULE_AM_SLOTRANGEARRAY: RM_ClusterFreeSlotRanges(NULL, ptr); break;
2675	        }
2676	    }
2677	    ctx->flags |= REDISMODULE_CTX_AUTO_MEMORY;
2678	    zfree(ctx->amqueue);
2679	    ctx->amqueue = NULL;
2680	    ctx->amqueue_len = 0;
2681	    ctx->amqueue_used = 0;
2682	}
