2820	 * This API is not thread safe, access to these retained strings (if they originated
2821	 * from a client command arguments) must be done with GIL locked. */
2822	void RM_FreeString(RedisModuleCtx *ctx, RedisModuleString *str) {
2823	    decrRefCount(str);
2824	    if (ctx != NULL) autoMemoryFreed(ctx,REDISMODULE_AM_STRING,str);
