2877	/**
2878	* This function can be used instead of RedisModule_RetainString().
2879	* The main difference between the two is that this function will always
2880	* succeed, whereas RedisModule_RetainString() may fail because of an
2881	* assertion.
2882	*
2883	* The function returns a pointer to RedisModuleString, which is owned
2884	* by the caller. It requires a call to RedisModule_FreeString() to free
2885	* the string when automatic memory management is disabled for the context.
2886	* When automatic memory management is enabled, you can either call
2887	* RedisModule_FreeString() or let the automation free it.
2888	*
2889	* This function is more efficient than RedisModule_CreateStringFromString()
2890	* because whenever possible, it avoids copying the underlying
2891	* RedisModuleString. The disadvantage of using this function is that it
2892	* might not be possible to use RedisModule_StringAppendBuffer() on the
2893	* returned RedisModuleString.
2894	*
2895	* It is possible to call this function with a NULL context.
2896	*
2897	 * When strings are going to be held for an extended duration, it is good
2898	 * practice to also call RedisModule_TrimStringAllocation() in order to
2899	 * optimize memory usage.
2900	 *
2901	 * Threaded modules that reference held strings from other threads *must*
2902	 * explicitly trim the allocation as soon as the string is held. Not doing
2903	 * so may result with automatic trimming which is not thread safe.
2904	 *
2905	 * This API is not thread safe, access to these retained strings (if they originated
2906	 * from a client command arguments) must be done with GIL locked. */
2907	RedisModuleString* RM_HoldString(RedisModuleCtx *ctx, RedisModuleString *str) {
2908	    if (str->refcount == OBJ_STATIC_REFCOUNT) {
2909	        return RM_CreateStringFromString(ctx, str);
2910	    }
2911	
2912	    incrRefCount(str);
2913	    if (ctx != NULL) {
2914	        /*
2915	         * Put the str in the auto memory management of the ctx.
2916	         * It might already be there, in this case, the ref count will
2917	         * be 2 and we will decrease the ref count twice and free the
2918	         * object in the auto memory free function.
2919	         *
2920	         * Why we can not do the same trick of just remove the object
2921	         * from the auto memory (like in RM_RetainString)?
2922	         * This code shows the issue:
2923	         *
2924	         * RM_AutoMemory(ctx);
2925	         * str1 = RM_CreateString(ctx, "test", 4);
2926	         * str2 = RM_HoldString(ctx, str1);
2927	         * RM_FreeString(str1);
2928	         * RM_FreeString(str2);
2929	         *
2930	         * If after the RM_HoldString we would just remove the string from
2931	         * the auto memory, this example will cause access to a freed memory
2932	         * on 'RM_FreeString(str2);' because the String will be free
2933	         * on 'RM_FreeString(str1);'.
2934	         *
2935	         * So it's safer to just increase the ref count
2936	         * and add the String to auto memory again.
2937	         *
2938	         * The limitation is that it is not possible to use RedisModule_StringAppendBuffer
2939	         * on the String.
2940	         */
2941	        autoMemoryAdd(ctx,REDISMODULE_AM_STRING,str);
2942	    }
2943	    return str;
2944	}
