2950	    if (str == NULL) {
2951	        const char *errmsg = "(NULL string reply referenced in module)";
2952	        if (len) *len = strlen(errmsg);
2953	        return errmsg;
2954	    }
2955	    if (len) *len = sdslen(str->ptr);
2956	    return str->ptr;
2957	}
