3019	/* Return the (possibly modified in encoding) input 'str' object if
3020	 * the string is unshared, otherwise NULL is returned. */
3021	RedisModuleString *moduleAssertUnsharedString(RedisModuleString *str) {
3022	    if (str->refcount != 1) {
3023	        serverLog(LL_WARNING,
3024	            "Module attempted to use an in-place string modify operation "
3025	            "with a string referenced multiple times. Please check the code "
3026	            "for API usage correctness.");
3027	        return NULL;
3028	    }
3029	    if (str->encoding == OBJ_ENCODING_EMBSTR) {
3030	        /* Note: here we "leak" the additional allocation that was
3031	         * used in order to store the embedded string in the object. */
3032	        str->ptr = sdsnewlen(str->ptr,sdslen(str->ptr));
3033	        str->encoding = OBJ_ENCODING_RAW;
3034	    } else if (str->encoding == OBJ_ENCODING_INT) {
3035	        /* Convert the string from integer to raw encoding. */
3036	        str->ptr = sdsfromlonglong((long)str->ptr);
3037	        str->encoding = OBJ_ENCODING_RAW;
3038	    }
3039	    return str;
3040	}
