3042	/* Append the specified buffer to the string 'str'. The string must be a
3043	 * string created by the user that is referenced only a single time, otherwise
3044	 * REDISMODULE_ERR is returned and the operation is not performed. */
3045	int RM_StringAppendBuffer(RedisModuleCtx *ctx, RedisModuleString *str, const char *buf, size_t len) {
3046	    UNUSED(ctx);
3047	    str = moduleAssertUnsharedString(str);
3048	    if (str == NULL) return REDISMODULE_ERR;
3049	    str->ptr = sdscatlen(str->ptr,buf,len);
3050	    return REDISMODULE_OK;
3051	}
