3053	/* Trim possible excess memory allocated for a RedisModuleString.
3054	 *
3055	 * Sometimes a RedisModuleString may have more memory allocated for
3056	 * it than required, typically for argv arguments that were constructed
3057	 * from network buffers. This function optimizes such strings by reallocating
3058	 * their memory, which is useful for strings that are not short lived but
3059	 * retained for an extended duration.
3060	 *
3061	 * This operation is *not thread safe* and should only be called when
3062	 * no concurrent access to the string is guaranteed. Using it for an argv
3063	 * string in a module command before the string is potentially available
3064	 * to other threads is generally safe.
3065	 *
3066	 * Currently, Redis may also automatically trim retained strings when a
3067	 * module command returns. However, doing this explicitly should still be
3068	 * a preferred option:
3069	 *
3070	 * 1. Future versions of Redis may abandon auto-trimming.
3071	 * 2. Auto-trimming as currently implemented is *not thread safe*.
3072	 *    A background thread manipulating a recently retained string may end up
3073	 *    in a race condition with the auto-trim, which could result with
3074	 *    data corruption.
3075	 */
3076	void RM_TrimStringAllocation(RedisModuleString *str) {
3077	    if (!str) return;
3078	    trimStringObjectIfNeeded(str, 1);
3079	}
