3081	/* --------------------------------------------------------------------------
3082	 * ## Reply APIs
3083	 *
3084	 * These functions are used for sending replies to the client.
3085	 *
3086	 * Most functions always return REDISMODULE_OK so you can use it with
3087	 * 'return' in order to return from the command implementation with:
3088	 *
3089	 *     if (... some condition ...)
3090	 *         return RedisModule_ReplyWithLongLong(ctx,mycount);
3091	 *
3092	 * ### Reply with collection functions
3093	 *
3094	 * After starting a collection reply, the module must make calls to other
3095	 * `ReplyWith*` style functions in order to emit the elements of the collection.
3096	 * Collection types include: Array, Map, Set and Attribute.
3097	 *
3098	 * When producing collections with a number of elements that is not known
3099	 * beforehand, the function can be called with a special flag
3100	 * REDISMODULE_POSTPONED_LEN (REDISMODULE_POSTPONED_ARRAY_LEN in the past),
3101	 * and the actual number of elements can be later set with RM_ReplySet*Length()
3102	 * call (which will set the latest "open" count if there are multiple ones).
3103	 * -------------------------------------------------------------------------- */
3104	
3105	/* Send an error about the number of arguments given to the command,
3106	 * citing the command name in the error message. Returns REDISMODULE_OK.
3107	 *
3108	 * Example:
3109	 *
3110	 *     if (argc != 3) return RedisModule_WrongArity(ctx);
3111	 */
3112	int RM_WrongArity(RedisModuleCtx *ctx) {
3113	    addReplyErrorArity(ctx->client);
3114	    return REDISMODULE_OK;
3115	}
3116	
3117	/* Return the client object the `RM_Reply*` functions should target.
3118	 * Normally this is just `ctx->client`, that is the client that called
3119	 * the module command, however in the case of thread safe contexts there
3120	 * is no directly associated client (since it would not be safe to access
3121	 * the client from a thread), so instead the blocked client object referenced
3122	 * in the thread safe context, has a fake client that we just use to accumulate
3123	 * the replies. Later, when the client is unblocked, the accumulated replies
3124	 * are appended to the actual client.
3125	 *
3126	 * The function returns the client pointer depending on the context, or
3127	 * NULL if there is no potential client. This happens when we are in the
3128	 * context of a thread safe context that was not initialized with a blocked
3129	 * client object. Other contexts without associated clients are the ones
3130	 * initialized to run the timers callbacks. */
3131	client *moduleGetReplyClient(RedisModuleCtx *ctx) {
3132	    if (ctx->flags & REDISMODULE_CTX_THREAD_SAFE) {
3133	        if (ctx->blocked_client)
3134	            return ctx->blocked_client->reply_client;
3135	        else
3136	            return NULL;
3137	    } else {
3138	        /* If this is a non thread safe context, just return the client
3139	         * that is running the command if any. This may be NULL as well
3140	         * in the case of contexts that are not executed with associated
3141	         * clients, like timer contexts. */
3142	        return ctx->client;
3143	    }
3144	}
