3227	int moduleReplyWithCollection(RedisModuleCtx *ctx, long len, int type) {
3228	    client *c = moduleGetReplyClient(ctx);
3229	    if (c == NULL) return REDISMODULE_OK;
3230	    if (len == REDISMODULE_POSTPONED_LEN) {
3231	        ctx->postponed_arrays = zrealloc(ctx->postponed_arrays,sizeof(void*)*
3232	                (ctx->postponed_arrays_count+1));
3233	        ctx->postponed_arrays[ctx->postponed_arrays_count] =
3234	            addReplyDeferredLen(c);
3235	        ctx->postponed_arrays_count++;
3236	    } else if (len == 0) {
3237	        switch (type) {
3238	        case COLLECTION_REPLY_ARRAY:
3239	            addReply(c, shared.emptyarray);
3240	            break;
3241	        case COLLECTION_REPLY_MAP:
3242	            addReply(c, shared.emptymap[c->resp]);
3243	            break;
3244	        case COLLECTION_REPLY_SET:
3245	            addReply(c, shared.emptyset[c->resp]);
3246	            break;
3247	        case COLLECTION_REPLY_ATTRIBUTE:
3248	            addReplyAttributeLen(c,len);
3249	            break;
3250	        default:
3251	            serverPanic("Invalid module empty reply type %d", type);        }
3252	    } else {
3253	        switch (type) {
3254	        case COLLECTION_REPLY_ARRAY:
3255	            addReplyArrayLen(c,len);
3256	            break;
3257	        case COLLECTION_REPLY_MAP:
3258	            addReplyMapLen(c,len);
3259	            break;
3260	        case COLLECTION_REPLY_SET:
3261	            addReplySetLen(c,len);
3262	            break;
3263	        case COLLECTION_REPLY_ATTRIBUTE:
3264	            addReplyAttributeLen(c,len);
3265	            break;
3266	        default:
3267	            serverPanic("Invalid module reply type %d", type);
3268	        }
3269	    }
3270	    return REDISMODULE_OK;
3271	}
