3363	void moduleReplySetCollectionLength(RedisModuleCtx *ctx, long len, int type) {
3364	    client *c = moduleGetReplyClient(ctx);
3365	    if (c == NULL) return;
3366	    if (ctx->postponed_arrays_count == 0) {
3367	        serverLog(LL_WARNING,
3368	            "API misuse detected in module %s: "
3369	            "RedisModule_ReplySet*Length() called without previous "
3370	            "RedisModule_ReplyWith*(ctx,REDISMODULE_POSTPONED_LEN) "
3371	            "call.", ctx->module->name);
3372	            return;
3373	    }
3374	    ctx->postponed_arrays_count--;
3375	    switch(type) {
3376	    case COLLECTION_REPLY_ARRAY:
3377	        setDeferredArrayLen(c,ctx->postponed_arrays[ctx->postponed_arrays_count],len);
3378	        break;
3379	    case COLLECTION_REPLY_MAP:
3380	        setDeferredMapLen(c,ctx->postponed_arrays[ctx->postponed_arrays_count],len);
3381	        break;
3382	    case COLLECTION_REPLY_SET:
3383	        setDeferredSetLen(c,ctx->postponed_arrays[ctx->postponed_arrays_count],len);
3384	        break;
3385	    case COLLECTION_REPLY_ATTRIBUTE:
3386	        setDeferredAttributeLen(c,ctx->postponed_arrays[ctx->postponed_arrays_count],len);
3387	        break;
3388	    default:
3389	        serverPanic("Invalid module reply type %d", type);
3390	    }
3391	    if (ctx->postponed_arrays_count == 0) {
3392	        zfree(ctx->postponed_arrays);
3393	        ctx->postponed_arrays = NULL;
3394	    }
3395	}
