3397	/* When RedisModule_ReplyWithArray() is used with the argument
3398	 * REDISMODULE_POSTPONED_LEN, because we don't know beforehand the number
3399	 * of items we are going to output as elements of the array, this function
3400	 * will take care to set the array length.
3401	 *
3402	 * Since it is possible to have multiple array replies pending with unknown
3403	 * length, this function guarantees to always set the latest array length
3404	 * that was created in a postponed way.
3405	 *
3406	 * For example in order to output an array like [1,[10,20,30]] we
3407	 * could write:
3408	 *
3409	 *      RedisModule_ReplyWithArray(ctx,REDISMODULE_POSTPONED_LEN);
3410	 *      RedisModule_ReplyWithLongLong(ctx,1);
3411	 *      RedisModule_ReplyWithArray(ctx,REDISMODULE_POSTPONED_LEN);
3412	 *      RedisModule_ReplyWithLongLong(ctx,10);
3413	 *      RedisModule_ReplyWithLongLong(ctx,20);
3414	 *      RedisModule_ReplyWithLongLong(ctx,30);
3415	 *      RedisModule_ReplySetArrayLength(ctx,3); // Set len of 10,20,30 array.
3416	 *      RedisModule_ReplySetArrayLength(ctx,2); // Set len of top array
3417	 *
3418	 * Note that in the above example there is no reason to postpone the array
3419	 * length, since we produce a fixed number of elements, but in the practice
3420	 * the code may use an iterator or other ways of creating the output so
3421	 * that is not easy to calculate in advance the number of elements.
3422	 */
3423	void RM_ReplySetArrayLength(RedisModuleCtx *ctx, long len) {
3424	    moduleReplySetCollectionLength(ctx, len, COLLECTION_REPLY_ARRAY);
3425	}
