3537	/* Reply exactly what a Redis command returned us with RedisModule_Call().
3538	 * This function is useful when we use RedisModule_Call() in order to
3539	 * execute some command, as we want to reply to the client exactly the
3540	 * same reply we obtained by the command.
3541	 *
3542	 * Return:
3543	 * - REDISMODULE_OK on success.
3544	 * - REDISMODULE_ERR if the given reply is in RESP3 format but the client expects RESP2.
3545	 *   In case of an error, it's the module writer responsibility to translate the reply
3546	 *   to RESP2 (or handle it differently by returning an error). Notice that for
3547	 *   module writer convenience, it is possible to pass `0` as a parameter to the fmt
3548	 *   argument of `RM_Call` so that the RedisModuleCallReply will return in the same
3549	 *   protocol (RESP2 or RESP3) as set in the current client's context. */
3550	int RM_ReplyWithCallReply(RedisModuleCtx *ctx, RedisModuleCallReply *reply) {
3551	    client *c = moduleGetReplyClient(ctx);
3552	    if (c == NULL) return REDISMODULE_OK;
3553	    if (c->resp == 2 && callReplyIsResp3(reply)) {
3554	        /* The reply is in RESP3 format and the client is RESP2,
3555	         * so it isn't possible to send this reply to the client. */
3556	        return REDISMODULE_ERR;
3557	    }
3558	    size_t proto_len;
3559	    const char *proto = callReplyGetProto(reply, &proto_len);
3560	    addReplyProto(c, proto, proto_len);
3561	    /* Propagate the error list from that reply to the other client, to do some
3562	     * post error reply handling, like statistics.
3563	     * Note that if the original reply had an array with errors, and the module
3564	     * replied with just a portion of the original reply, and not the entire
3565	     * reply, the errors are currently not propagated and the errors stats
3566	     * will not get propagated. */
3567	    list *errors = callReplyDeferredErrorList(reply);
3568	    if (errors)
3569	        deferredAfterErrorReply(c, errors);
3570	    return REDISMODULE_OK;
3571	}
