3622	/* --------------------------------------------------------------------------
3623	 * ## Commands replication API
3624	 * -------------------------------------------------------------------------- */
3625	
3626	/* Replicate the specified command and arguments to slaves and AOF, as effect
3627	 * of execution of the calling command implementation.
3628	 *
3629	 * The replicated commands are always wrapped into the MULTI/EXEC that
3630	 * contains all the commands replicated in a given module command
3631	 * execution, in the order they were executed.
3632	 *
3633	 * Modules should try to use one interface or the other.
3634	 *
3635	 * This command follows exactly the same interface of RedisModule_Call(),
3636	 * so a set of format specifiers must be passed, followed by arguments
3637	 * matching the provided format specifiers.
3638	 *
3639	 * Please refer to RedisModule_Call() for more information.
3640	 *
3641	 * Using the special "A" and "R" modifiers, the caller can exclude either
3642	 * the AOF or the replicas from the propagation of the specified command.
3643	 * Otherwise, by default, the command will be propagated in both channels.
3644	 *
3645	 * #### Note about calling this function from a thread safe context:
3646	 *
3647	 * Normally when you call this function from the callback implementing a
3648	 * module command, or any other callback provided by the Redis Module API,
3649	 * Redis will accumulate all the calls to this function in the context of
3650	 * the callback, and will propagate all the commands wrapped in a MULTI/EXEC
3651	 * transaction. However when calling this function from a threaded safe context
3652	 * that can live an undefined amount of time, and can be locked/unlocked in
3653	 * at will, it is important to note that this API is not thread-safe and
3654	 * must be executed while holding the GIL.
3655	 *
3656	 * #### Return value
3657	 *
3658	 * The command returns REDISMODULE_ERR if the format specifiers are invalid
3659	 * or the command name does not belong to a known command. */
3660	int RM_Replicate(RedisModuleCtx *ctx, const char *cmdname, const char *fmt, ...) {
3661	    struct redisCommand *cmd;
3662	    robj **argv = NULL;
3663	    int argc = 0, flags = 0, j;
3664	    va_list ap;
3665	
3666	    cmd = lookupCommandByCString((char*)cmdname);
3667	    if (!cmd) return REDISMODULE_ERR;
3668	
3669	    /* Create the client and dispatch the command. */
3670	    va_start(ap, fmt);
3671	    argv = moduleCreateArgvFromUserFormat(cmdname,fmt,&argc,&flags,ap);
3672	    va_end(ap);
3673	    if (argv == NULL) return REDISMODULE_ERR;
3674	
3675	    /* Select the propagation target. Usually is AOF + replicas, however
3676	     * the caller can exclude one or the other using the "A" or "R"
3677	     * modifiers. */
3678	    int target = 0;
3679	    if (!(flags & REDISMODULE_ARGV_NO_AOF)) target |= PROPAGATE_AOF;
3680	    if (!(flags & REDISMODULE_ARGV_NO_REPLICAS)) target |= PROPAGATE_REPL;
3681	
3682	    alsoPropagate(ctx->client->db->id,argv,argc,target);
3683	
3684	    /* Release the argv. */
3685	    for (j = 0; j < argc; j++) decrRefCount(argv[j]);
3686	    zfree(argv);
3687	    server.dirty++;
3688	    return REDISMODULE_OK;
3689	}
3690	
3691	/* This function will replicate the command exactly as it was invoked
3692	 * by the client. Note that the replicated commands are always wrapped
3693	 * into the MULTI/EXEC that contains all the commands replicated in a
3694	 * given module command execution, in the order they were executed.
3695	 *
3696	 * Basically this form of replication is useful when you want to propagate
3697	 * the command to the slaves and AOF file exactly as it was called, since
3698	 * the command can just be re-executed to deterministically re-create the
3699	 * new state starting from the old one.
3700	 *
3701	 * It is important to note that this API is not thread-safe and
3702	 * must be executed while holding the GIL.
3703	 *
3704	 * The function always returns REDISMODULE_OK. */
3705	int RM_ReplicateVerbatim(RedisModuleCtx *ctx) {
3706	    alsoPropagate(ctx->client->db->id,
3707	        ctx->client->argv,ctx->client->argc,
3708	        PROPAGATE_AOF|PROPAGATE_REPL);
3709	    server.dirty++;
3710	    return REDISMODULE_OK;
3711	}
