3717	/* Return the ID of the current client calling the currently active module
3718	 * command. The returned ID has a few guarantees:
3719	 *
3720	 * 1. The ID is different for each different client, so if the same client
3721	 *    executes a module command multiple times, it can be recognized as
3722	 *    having the same ID, otherwise the ID will be different.
3723	 * 2. The ID increases monotonically. Clients connecting to the server later
3724	 *    are guaranteed to get IDs greater than any past ID previously seen.
3725	 *
3726	 * Valid IDs are from 1 to 2^64 - 1. If 0 is returned it means there is no way
3727	 * to fetch the ID in the context the function was currently called.
3728	 *
3729	 * After obtaining the ID, it is possible to check if the command execution
3730	 * is actually happening in the context of AOF loading, using this macro:
3731	 *
3732	 *      if (RedisModule_IsAOFClient(RedisModule_GetClientId(ctx)) {
3733	 *          // Handle it differently.
3734	 *      }
3735	 */
3736	unsigned long long RM_GetClientId(RedisModuleCtx *ctx) {
3737	    if (ctx->client == NULL) return 0;
3738	    return ctx->client->id;
3739	}
