3763	/* This is a helper for RM_GetClientInfoById() and other functions: given
3764	 * a client, it populates the client info structure with the appropriate
3765	 * fields depending on the version provided. If the version is not valid
3766	 * then REDISMODULE_ERR is returned. Otherwise the function returns
3767	 * REDISMODULE_OK and the structure pointed by 'ci' gets populated. */
3768	
3769	int modulePopulateClientInfoStructure(void *ci, client *client, int structver) {
3770	    if (structver != 1) return REDISMODULE_ERR;
3771	
3772	    RedisModuleClientInfoV1 *ci1 = ci;
3773	    memset(ci1,0,sizeof(*ci1));
3774	    ci1->version = structver;
3775	    if (client->flags & CLIENT_MULTI)
3776	        ci1->flags |= REDISMODULE_CLIENTINFO_FLAG_MULTI;
3777	    if (client->flags & CLIENT_PUBSUB)
3778	        ci1->flags |= REDISMODULE_CLIENTINFO_FLAG_PUBSUB;
3779	    if (client->flags & CLIENT_UNIX_SOCKET)
3780	        ci1->flags |= REDISMODULE_CLIENTINFO_FLAG_UNIXSOCKET;
3781	    if (client->flags & CLIENT_TRACKING)
3782	        ci1->flags |= REDISMODULE_CLIENTINFO_FLAG_TRACKING;
3783	    if (client->flags & CLIENT_BLOCKED)
3784	        ci1->flags |= REDISMODULE_CLIENTINFO_FLAG_BLOCKED;
3785	    if (client->conn->type == connectionTypeTls())
3786	        ci1->flags |= REDISMODULE_CLIENTINFO_FLAG_SSL;
3787	
3788	    int port;
3789	    connAddrPeerName(client->conn,ci1->addr,sizeof(ci1->addr),&port);
3790	    ci1->port = port;
3791	    ci1->db = client->db->id;
3792	    ci1->id = client->id;
3793	    return REDISMODULE_OK;
3794	}
