3817	/* Return information about the client with the specified ID (that was
3818	 * previously obtained via the RedisModule_GetClientId() API). If the
3819	 * client exists, REDISMODULE_OK is returned, otherwise REDISMODULE_ERR
3820	 * is returned.
3821	 *
3822	 * When the client exist and the `ci` pointer is not NULL, but points to
3823	 * a structure of type RedisModuleClientInfoV1, previously initialized with
3824	 * the correct REDISMODULE_CLIENTINFO_INITIALIZER_V1, the structure is populated
3825	 * with the following fields:
3826	 *
3827	 *      uint64_t flags;         // REDISMODULE_CLIENTINFO_FLAG_*
3828	 *      uint64_t id;            // Client ID
3829	 *      char addr[46];          // IPv4 or IPv6 address.
3830	 *      uint16_t port;          // TCP port.
3831	 *      uint16_t db;            // Selected DB.
3832	 *
3833	 * Note: the client ID is useless in the context of this call, since we
3834	 *       already know, however the same structure could be used in other
3835	 *       contexts where we don't know the client ID, yet the same structure
3836	 *       is returned.
3837	 *
3838	 * With flags having the following meaning:
3839	 *
3840	 *     REDISMODULE_CLIENTINFO_FLAG_SSL          Client using SSL connection.
3841	 *     REDISMODULE_CLIENTINFO_FLAG_PUBSUB       Client in Pub/Sub mode.
3842	 *     REDISMODULE_CLIENTINFO_FLAG_BLOCKED      Client blocked in command.
3843	 *     REDISMODULE_CLIENTINFO_FLAG_TRACKING     Client with keys tracking on.
3844	 *     REDISMODULE_CLIENTINFO_FLAG_UNIXSOCKET   Client using unix domain socket.
3845	 *     REDISMODULE_CLIENTINFO_FLAG_MULTI        Client in MULTI state.
3846	 *
3847	 * However passing NULL is a way to just check if the client exists in case
3848	 * we are not interested in any additional information.
3849	 *
3850	 * This is the correct usage when we want the client info structure
3851	 * returned:
3852	 *
3853	 *      RedisModuleClientInfo ci = REDISMODULE_CLIENTINFO_INITIALIZER;
3854	 *      int retval = RedisModule_GetClientInfoById(&ci,client_id);
3855	 *      if (retval == REDISMODULE_OK) {
3856	 *          printf("Address: %s\n", ci.addr);
3857	 *      }
3858	 */
3859	int RM_GetClientInfoById(void *ci, uint64_t id) {
3860	    client *client = lookupClientByID(id);
3861	    if (client == NULL) return REDISMODULE_ERR;
3862	    if (ci == NULL) return REDISMODULE_OK;
3863	
3864	    /* Fill the info structure if passed. */
3865	    uint64_t structver = ((uint64_t*)ci)[0];
3866	    return modulePopulateClientInfoStructure(ci,client,structver);
3867	}
