5003	/* Replaces the element at index `index` in the list stored at `key`.
5004	 *
5005	 * The index is zero-based, so 0 means the first element, 1 the second element
5006	 * and so on. Negative indices can be used to designate elements starting at the
5007	 * tail of the list. Here, -1 means the last element, -2 means the penultimate
5008	 * and so forth.
5009	 *
5010	 * On success, REDISMODULE_OK is returned. On failure, REDISMODULE_ERR is
5011	 * returned and `errno` is set as follows:
5012	 *
5013	 * - EINVAL if key or value is NULL.
5014	 * - ENOTSUP if the key is not a list.
5015	 * - EBADF if the key is not opened for writing.
5016	 * - EDOM if the index is not a valid index in the list.
5017	 */
5018	int RM_ListSet(RedisModuleKey *key, long index, RedisModuleString *value) {
5019	    size_t oldsize = 0;
5020	    if (!value) {
5021	        errno = EINVAL;
5022	        return REDISMODULE_ERR;
5023	    }
5024	    if (!key->kv || key->kv->type != OBJ_LIST) {
5025	        errno = ENOTSUP;
5026	        return REDISMODULE_ERR;
5027	    }
5028	    if (server.memory_tracking_enabled)
5029	        oldsize = kvobjAllocSize(key->kv);
5030	    listTypeTryConversionAppend(key->kv, &value, 0, 0, moduleFreeListIterator, key);
5031	    if (moduleListIteratorSeek(key, index, REDISMODULE_WRITE)) {
5032	        listTypeReplace(&key->u.list.entry, value);
5033	        if (server.memory_tracking_enabled)
5034	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5035	        /* A note in quicklist.c forbids use of iterator after insert, so
5036	         * probably also after replace. */
5037	        moduleFreeKeyIterator(key);
5038	        return REDISMODULE_OK;
5039	    } else {
5040	        if (server.memory_tracking_enabled)
5041	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5042	        return REDISMODULE_ERR;
5043	    }
5044	}
5045	
5046	/* Inserts an element at the given index.
5047	 *
5048	 * The index is zero-based, so 0 means the first element, 1 the second element
5049	 * and so on. Negative indices can be used to designate elements starting at the
5050	 * tail of the list. Here, -1 means the last element, -2 means the penultimate
5051	 * and so forth. The index is the element's index after inserting it.
5052	 *
5053	 * On success, REDISMODULE_OK is returned. On failure, REDISMODULE_ERR is
5054	 * returned and `errno` is set as follows:
5055	 *
5056	 * - EINVAL if key or value is NULL.
5057	 * - ENOTSUP if the key of another type than list.
5058	 * - EBADF if the key is not opened for writing.
5059	 * - EDOM if the index is not a valid index in the list.
5060	 */
5061	int RM_ListInsert(RedisModuleKey *key, long index, RedisModuleString *value) {
5062	    size_t oldsize = 0;
5063	    if (!value) {
5064	        errno = EINVAL;
5065	        return REDISMODULE_ERR;
5066	    } else if (key != NULL && key->kv == NULL &&
5067	               (index == 0 || index == -1)) {
5068	        /* Insert in empty key => push. */
5069	        return RM_ListPush(key, REDISMODULE_LIST_TAIL, value);
5070	    } else if (key != NULL && key->kv != NULL &&
5071	               key->kv->type == OBJ_LIST &&
5072	               (index == (long)listTypeLength(key->kv) || index == -1)) {
5073	        /* Insert after the last element => push tail. */
5074	        return RM_ListPush(key, REDISMODULE_LIST_TAIL, value);
5075	    } else if (key != NULL && key->kv != NULL &&
5076	               key->kv->type == OBJ_LIST &&
5077	               (index == 0 || index == -(long)listTypeLength(key->kv) - 1)) {
5078	        /* Insert before the first element => push head. */
5079	        return RM_ListPush(key, REDISMODULE_LIST_HEAD, value);
5080	    }
5081	    if (server.memory_tracking_enabled)
5082	        oldsize = kvobjAllocSize(key->kv);
5083	    listTypeTryConversionAppend(key->kv, &value, 0, 0, moduleFreeListIterator, key);
5084	    if (moduleListIteratorSeek(key, index, REDISMODULE_WRITE)) {
5085	        int where = index < 0 ? LIST_TAIL : LIST_HEAD;
5086	        listTypeInsert(&key->u.list.entry, value, where);
5087	        int64_t l = (int64_t) listTypeLength(key->kv);
5088	        updateKeysizesHist(key->db, OBJ_LIST, l-1, l);
5089	        if (server.memory_tracking_enabled)
5090	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5091	        /* A note in quicklist.c forbids use of iterator after insert. */
5092	        moduleFreeKeyIterator(key);
5093	        return REDISMODULE_OK;
5094	    } else {
5095	        if (server.memory_tracking_enabled)
5096	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5097	        return REDISMODULE_ERR;
5098	    }
5099	}
5100	
5101	/* Removes an element at the given index. The index is 0-based. A negative index
5102	 * can also be used, counting from the end of the list.
5103	 *
5104	 * On success, REDISMODULE_OK is returned. On failure, REDISMODULE_ERR is
5105	 * returned and `errno` is set as follows:
5106	 *
5107	 * - EINVAL if key or value is NULL.
5108	 * - ENOTSUP if the key is not a list.
5109	 * - EBADF if the key is not opened for writing.
5110	 * - EDOM if the index is not a valid index in the list.
5111	 */
5112	int RM_ListDelete(RedisModuleKey *key, long index) {
5113	    if (moduleListIteratorSeek(key, index, REDISMODULE_WRITE)) {
5114	        size_t oldsize = 0;
5115	        if (server.memory_tracking_enabled)
5116	            oldsize = kvobjAllocSize(key->kv);
5117	        listTypeDelete(key->iter, &key->u.list.entry);
5118	        int64_t l = (int64_t) listTypeLength(key->kv);
5119	        updateKeysizesHist(key->db, OBJ_LIST, l+1, l);
5120	        if (server.memory_tracking_enabled)
5121	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5122	        if (moduleDelKeyIfEmpty(key)) return REDISMODULE_OK;
5123	        if (server.memory_tracking_enabled)
5124	            oldsize = kvobjAllocSize(key->kv);
5125	        listTypeTryConversion(key->kv, LIST_CONV_SHRINKING, moduleFreeListIterator, key);
5126	        if (server.memory_tracking_enabled)
5127	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5128	        if (!key->iter) return REDISMODULE_OK; /* Return ASAP if iterator has been freed */
5129	        if (listTypeNext(key->iter, &key->u.list.entry)) {
5130	            /* After delete entry at position 'index', we need to update
5131	             * 'key->u.list.index' according to the following cases:
5132	             * 1) [1, 2, 3] => dir: forward, index: 0  => [2, 3] => index: still 0
5133	             * 2) [1, 2, 3] => dir: forward, index: -3 => [2, 3] => index: -2
5134	             * 3) [1, 2, 3] => dir: reverse, index: 2  => [1, 2] => index: 1
5135	             * 4) [1, 2, 3] => dir: reverse, index: -1 => [1, 2] => index: still -1 */
5136	            listTypeIterator *li = key->iter;
5137	            int reverse = li->direction == LIST_HEAD;
5138	            if (key->u.list.index < 0)
5139	                key->u.list.index += reverse ? 0 : 1;
5140	            else
5141	                key->u.list.index += reverse ? -1 : 0;
5142	        } else {
5143	            /* Reset list iterator if the next entry doesn't exist. */
5144	            moduleFreeKeyIterator(key);
5145	        }
5146	        return REDISMODULE_OK;
5147	    } else {
5148	        return REDISMODULE_ERR;
5149	    }
5150	}
