5157	
5158	/* Conversion from/to public flags of the Modules API and our private flags,
5159	 * so that we have everything decoupled. */
5160	int moduleZsetAddFlagsToCoreFlags(int flags) {
5161	    int retflags = 0;
5162	    if (flags & REDISMODULE_ZADD_XX) retflags |= ZADD_IN_XX;
5163	    if (flags & REDISMODULE_ZADD_NX) retflags |= ZADD_IN_NX;
5164	    if (flags & REDISMODULE_ZADD_GT) retflags |= ZADD_IN_GT;
5165	    if (flags & REDISMODULE_ZADD_LT) retflags |= ZADD_IN_LT;
5166	    return retflags;
5167	}
5168	
5169	/* See previous function comment. */
5170	int moduleZsetAddFlagsFromCoreFlags(int flags) {
5171	    int retflags = 0;
5172	    if (flags & ZADD_OUT_ADDED) retflags |= REDISMODULE_ZADD_ADDED;
5173	    if (flags & ZADD_OUT_UPDATED) retflags |= REDISMODULE_ZADD_UPDATED;
5174	    if (flags & ZADD_OUT_NOP) retflags |= REDISMODULE_ZADD_NOP;
5175	    return retflags;
5176	}
