5178	/* Add a new element into a sorted set, with the specified 'score'.
5179	 * If the element already exists, the score is updated.
5180	 *
5181	 * A new sorted set is created at value if the key is an empty open key
5182	 * setup for writing.
5183	 *
5184	 * Additional flags can be passed to the function via a pointer, the flags
5185	 * are both used to receive input and to communicate state when the function
5186	 * returns. 'flagsptr' can be NULL if no special flags are used.
5187	 *
5188	 * The input flags are:
5189	 *
5190	 *     REDISMODULE_ZADD_XX: Element must already exist. Do nothing otherwise.
5191	 *     REDISMODULE_ZADD_NX: Element must not exist. Do nothing otherwise.
5192	 *     REDISMODULE_ZADD_GT: If element exists, new score must be greater than the current score. 
5193	 *                          Do nothing otherwise. Can optionally be combined with XX.
5194	 *     REDISMODULE_ZADD_LT: If element exists, new score must be less than the current score.
5195	 *                          Do nothing otherwise. Can optionally be combined with XX.
5196	 *
5197	 * The output flags are:
5198	 *
5199	 *     REDISMODULE_ZADD_ADDED: The new element was added to the sorted set.
5200	 *     REDISMODULE_ZADD_UPDATED: The score of the element was updated.
5201	 *     REDISMODULE_ZADD_NOP: No operation was performed because XX or NX flags.
5202	 *
5203	 * On success the function returns REDISMODULE_OK. On the following errors
5204	 * REDISMODULE_ERR is returned:
5205	 *
5206	 * * The key was not opened for writing.
5207	 * * The key is of the wrong type.
5208	 * * 'score' double value is not a number (NaN).
5209	 */
5210	int RM_ZsetAdd(RedisModuleKey *key, double score, RedisModuleString *ele, int *flagsptr) {
5211	    int in_flags = 0, out_flags = 0;
5212	    size_t oldsize = 0;
5213	    if (!(key->mode & REDISMODULE_WRITE)) return REDISMODULE_ERR;
5214	    if (key->kv && key->kv->type != OBJ_ZSET) return REDISMODULE_ERR;
5215	    if (key->kv == NULL) moduleCreateEmptyKey(key,REDISMODULE_KEYTYPE_ZSET);
5216	    if (server.memory_tracking_enabled)
5217	        oldsize = kvobjAllocSize(key->kv);
5218	    if (flagsptr) in_flags = moduleZsetAddFlagsToCoreFlags(*flagsptr);
5219	    if (zsetAdd(key->kv,score,ele->ptr,in_flags,&out_flags,NULL) == 0) {
5220	        if (flagsptr) *flagsptr = 0;
5221	        if (server.memory_tracking_enabled)
5222	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5223	        moduleDelKeyIfEmpty(key);
5224	        return REDISMODULE_ERR;
5225	    }
5226	    if (flagsptr) *flagsptr = moduleZsetAddFlagsFromCoreFlags(out_flags);
5227	    int64_t l = (int64_t) zsetLength(key->kv);
5228	    updateKeysizesHist(key->db, OBJ_ZSET, l-1, l);
5229	    if (server.memory_tracking_enabled)
5230	        updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5231	    return REDISMODULE_OK;
5232	}
5233	
5234	/* This function works exactly like RM_ZsetAdd(), but instead of setting
5235	 * a new score, the score of the existing element is incremented, or if the
5236	 * element does not already exist, it is added assuming the old score was
5237	 * zero.
5238	 *
5239	 * The input and output flags, and the return value, have the same exact
5240	 * meaning, with the only difference that this function will return
5241	 * REDISMODULE_ERR even when 'score' is a valid double number, but adding it
5242	 * to the existing score results into a NaN (not a number) condition.
5243	 *
5244	 * This function has an additional field 'newscore', if not NULL is filled
5245	 * with the new score of the element after the increment, if no error
5246	 * is returned. */
5247	int RM_ZsetIncrby(RedisModuleKey *key, double score, RedisModuleString *ele, int *flagsptr, double *newscore) {
5248	    int in_flags = 0, out_flags = 0;
5249	    size_t oldsize = 0;
5250	    if (!(key->mode & REDISMODULE_WRITE)) return REDISMODULE_ERR;
5251	    if (key->kv && key->kv->type != OBJ_ZSET) return REDISMODULE_ERR;
5252	    if (key->kv == NULL) moduleCreateEmptyKey(key,REDISMODULE_KEYTYPE_ZSET);
5253	    if (server.memory_tracking_enabled)
5254	        oldsize = kvobjAllocSize(key->kv);
5255	    if (flagsptr) in_flags = moduleZsetAddFlagsToCoreFlags(*flagsptr);
5256	    in_flags |= ZADD_IN_INCR;
5257	    if (zsetAdd(key->kv,score,ele->ptr,in_flags,&out_flags,newscore) == 0) {
5258	        if (flagsptr) *flagsptr = 0;
5259	        if (server.memory_tracking_enabled)
5260	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5261	        moduleDelKeyIfEmpty(key);
5262	        return REDISMODULE_ERR;
5263	    }
5264	    if (server.memory_tracking_enabled)
5265	        updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5266	    if (out_flags & ZADD_OUT_ADDED) {
5267	        int64_t l = (int64_t) zsetLength(key->kv);
5268	        updateKeysizesHist(key->db, OBJ_ZSET, l-1, l);
5269	    }
5270	    if (flagsptr) *flagsptr = moduleZsetAddFlagsFromCoreFlags(out_flags);
5271	    return REDISMODULE_OK;
5272	}
