5274	/* Remove the specified element from the sorted set.
5275	 * The function returns REDISMODULE_OK on success, and REDISMODULE_ERR
5276	 * on one of the following conditions:
5277	 *
5278	 * * The key was not opened for writing.
5279	 * * The key is of the wrong type.
5280	 *
5281	 * The return value does NOT indicate the fact the element was really
5282	 * removed (since it existed) or not, just if the function was executed
5283	 * with success.
5284	 *
5285	 * In order to know if the element was removed, the additional argument
5286	 * 'deleted' must be passed, that populates the integer by reference
5287	 * setting it to 1 or 0 depending on the outcome of the operation.
5288	 * The 'deleted' argument can be NULL if the caller is not interested
5289	 * to know if the element was really removed.
5290	 *
5291	 * Empty keys will be handled correctly by doing nothing. */
5292	int RM_ZsetRem(RedisModuleKey *key, RedisModuleString *ele, int *deleted) {
5293	    size_t oldsize = 0;
5294	    if (!(key->mode & REDISMODULE_WRITE)) return REDISMODULE_ERR;
5295	    if (key->kv == NULL) {
5296	        if (deleted) *deleted = 0;
5297	        return REDISMODULE_OK;
5298	    }
5299	    if (key->kv->type != OBJ_ZSET) return REDISMODULE_ERR;
5300	    if (server.memory_tracking_enabled)
5301	        oldsize = kvobjAllocSize(key->kv);
5302	    if (zsetDel(key->kv,ele->ptr)) {
5303	        if (deleted) *deleted = 1;
5304	        int64_t l = (int64_t) zsetLength(key->kv);
5305	        updateKeysizesHist(key->db, OBJ_ZSET, l+1, l);
5306	        if (server.memory_tracking_enabled)
5307	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5308	        moduleDelKeyIfEmpty(key);
5309	    } else {
5310	        if (deleted) *deleted = 0;
5311	        if (server.memory_tracking_enabled)
5312	            updateSlotAllocSize(key->db, getKeySlot(key->key->ptr), key->kv, oldsize, kvobjAllocSize(key->kv));
5313	    }
5314	    return REDISMODULE_OK;
5315	}
