5317	/* On success retrieve the double score associated at the sorted set element
5318	 * 'ele' and returns REDISMODULE_OK. Otherwise REDISMODULE_ERR is returned
5319	 * to signal one of the following conditions:
5320	 *
5321	 * * There is no such element 'ele' in the sorted set.
5322	 * * The key is not a sorted set.
5323	 * * The key is an open empty key.
5324	 */
5325	int RM_ZsetScore(RedisModuleKey *key, RedisModuleString *ele, double *score) {
5326	    if (key->kv == NULL) return REDISMODULE_ERR;
5327	    if (key->kv->type != OBJ_ZSET) return REDISMODULE_ERR;
5328	    if (zsetScore(key->kv,ele->ptr,score) == C_ERR) return REDISMODULE_ERR;
5329	    return REDISMODULE_OK;
5330	}
