5342	/* Stop a sorted set iteration. */
5343	void RM_ZsetRangeStop(RedisModuleKey *key) {
5344	    if (!key->kv || key->kv->type != OBJ_ZSET) return;
5345	    /* Free resources if needed. */
5346	    if (key->u.zset.type == REDISMODULE_ZSET_RANGE_LEX)
5347	        zslFreeLexRange(&key->u.zset.lrs);
5348	    /* Setup sensible values so that misused iteration API calls when an
5349	     * iterator is not active will result into something more sensible
5350	     * than crashing. */
5351	    zsetKeyReset(key);
5352	}
