5354	/* Return the "End of range" flag value to signal the end of the iteration. */
5355	int RM_ZsetRangeEndReached(RedisModuleKey *key) {
5356	    if (!key->kv || key->kv->type != OBJ_ZSET) return 1;
5357	    return key->u.zset.er;
