5360	/* Helper function for RM_ZsetFirstInScoreRange() and RM_ZsetLastInScoreRange().
5361	 * Setup the sorted set iteration according to the specified score range
5362	 * (see the functions calling it for more info). If 'first' is true the
5363	 * first element in the range is used as a starting point for the iterator
5364	 * otherwise the last. Return REDISMODULE_OK on success otherwise
5365	 * REDISMODULE_ERR. */
5366	int zsetInitScoreRange(RedisModuleKey *key, double min, double max, int minex, int maxex, int first) {
5367	    if (!key->kv || key->kv->type != OBJ_ZSET) return REDISMODULE_ERR;
5368	
5369	    RM_ZsetRangeStop(key);
5370	    key->u.zset.type = REDISMODULE_ZSET_RANGE_SCORE;
5371	    key->u.zset.er = 0;
5372	
5373	    /* Setup the range structure used by the sorted set core implementation
5374	     * in order to seek at the specified element. */
5375	    zrangespec *zrs = &key->u.zset.rs;
5376	    zrs->min = min;
5377	    zrs->max = max;
5378	    zrs->minex = minex;
5379	    zrs->maxex = maxex;
5380	
5381	    if (key->kv->encoding == OBJ_ENCODING_LISTPACK) {
5382	        key->u.zset.current = first ? zzlFirstInRange(key->kv->ptr,zrs) :
5383	                                      zzlLastInRange(key->kv->ptr,zrs);
5384	    } else if (key->kv->encoding == OBJ_ENCODING_SKIPLIST) {
5385	        zset *zs = key->kv->ptr;
5386	        zskiplist *zsl = zs->zsl;
5387	        key->u.zset.current = first ? zslNthInRange(zsl, zrs, 0, NULL) :
5388	                                      zslNthInRange(zsl, zrs, -1, NULL);
5389	    } else {
5390	        serverPanic("Unsupported zset encoding");
5391	    }
5392	    if (key->u.zset.current == NULL) key->u.zset.er = 1;
5393	    return REDISMODULE_OK;
5394	}
