5396	/* Setup a sorted set iterator seeking the first element in the specified
5397	 * range. Returns REDISMODULE_OK if the iterator was correctly initialized
5398	 * otherwise REDISMODULE_ERR is returned in the following conditions:
5399	 *
5400	 * 1. The value stored at key is not a sorted set or the key is empty.
5401	 *
5402	 * The range is specified according to the two double values 'min' and 'max'.
5403	 * Both can be infinite using the following two macros:
5404	 *
5405	 * * REDISMODULE_POSITIVE_INFINITE for positive infinite value
5406	 * * REDISMODULE_NEGATIVE_INFINITE for negative infinite value
5407	 *
5408	 * 'minex' and 'maxex' parameters, if true, respectively setup a range
5409	 * where the min and max value are exclusive (not included) instead of
5410	 * inclusive. */
5411	int RM_ZsetFirstInScoreRange(RedisModuleKey *key, double min, double max, int minex, int maxex) {
5412	    return zsetInitScoreRange(key,min,max,minex,maxex,1);
5413	}
5414	
5415	/* Exactly like RedisModule_ZsetFirstInScoreRange() but the last element of
5416	 * the range is selected for the start of the iteration instead. */
