5421	/* Helper function for RM_ZsetFirstInLexRange() and RM_ZsetLastInLexRange().
5422	 * Setup the sorted set iteration according to the specified lexicographical
5423	 * range (see the functions calling it for more info). If 'first' is true the
5424	 * first element in the range is used as a starting point for the iterator
5425	 * otherwise the last. Return REDISMODULE_OK on success otherwise
5426	 * REDISMODULE_ERR.
5427	 *
5428	 * Note that this function takes 'min' and 'max' in the same form of the
5429	 * Redis ZRANGEBYLEX command. */
5430	int zsetInitLexRange(RedisModuleKey *key, RedisModuleString *min, RedisModuleString *max, int first) {
5431	    if (!key->kv || key->kv->type != OBJ_ZSET) return REDISMODULE_ERR;
5432	
5433	    RM_ZsetRangeStop(key);
5434	    key->u.zset.er = 0;
5435	
5436	    /* Setup the range structure used by the sorted set core implementation
5437	     * in order to seek at the specified element. */
5438	    zlexrangespec *zlrs = &key->u.zset.lrs;
5439	    if (zslParseLexRange(min, max, zlrs) == C_ERR) return REDISMODULE_ERR;
5440	
5441	    /* Set the range type to lex only after successfully parsing the range,
5442	     * otherwise we don't want the zlexrangespec to be freed. */
5443	    key->u.zset.type = REDISMODULE_ZSET_RANGE_LEX;
5444	
5445	    if (key->kv->encoding == OBJ_ENCODING_LISTPACK) {
5446	        key->u.zset.current = first ? zzlFirstInLexRange(key->kv->ptr,zlrs) :
5447	                                      zzlLastInLexRange(key->kv->ptr,zlrs);
5448	    } else if (key->kv->encoding == OBJ_ENCODING_SKIPLIST) {
5449	        zset *zs = key->kv->ptr;
5450	        zskiplist *zsl = zs->zsl;
5451	        key->u.zset.current = first ? zslNthInLexRange(zsl,zlrs,0,NULL) :
5452	                                      zslNthInLexRange(zsl,zlrs,-1,NULL);
5453	    } else {
5454	        serverPanic("Unsupported zset encoding");
5455	    }
5456	    if (key->u.zset.current == NULL) key->u.zset.er = 1;
5457	
5458	    return REDISMODULE_OK;
5459	}
