5461	/* Setup a sorted set iterator seeking the first element in the specified
5462	 * lexicographical range. Returns REDISMODULE_OK if the iterator was correctly
5463	 * initialized otherwise REDISMODULE_ERR is returned in the
5464	 * following conditions:
5465	 *
5466	 * 1. The value stored at key is not a sorted set or the key is empty.
5467	 * 2. The lexicographical range 'min' and 'max' format is invalid.
5468	 *
5469	 * 'min' and 'max' should be provided as two RedisModuleString objects
5470	 * in the same format as the parameters passed to the ZRANGEBYLEX command.
5471	 * The function does not take ownership of the objects, so they can be released
5472	 * ASAP after the iterator is setup. */
5473	int RM_ZsetFirstInLexRange(RedisModuleKey *key, RedisModuleString *min, RedisModuleString *max) {
5474	    return zsetInitLexRange(key,min,max,1);
5475	}
