5491	    if (key->kv->encoding == OBJ_ENCODING_LISTPACK) {
5492	        unsigned char *eptr, *sptr;
5493	        eptr = key->u.zset.current;
5494	        sds ele = lpGetObject(eptr);
5495	        if (score) {
5496	            sptr = lpNext(key->kv->ptr,eptr);
