5499	        str = createObject(OBJ_STRING,ele);

7500	 * * **unlink2**: Similar to `unlink`, but provides the `RedisModuleKeyOptCtx` parameter
7501	 *   so that meta information such as key name and db id can be obtained.
7502	 * * **copy2**: Similar to `copy`, but provides the `RedisModuleKeyOptCtx` parameter
7503	 *   so that meta information such as key names and db ids can be obtained.
7504	 * * **aux_save2**: Similar to `aux_save`, but with small semantic change, if the module
7505	 *   saves nothing on this callback then no data about this aux field will be written to the
7506	 *   RDB and it will be possible to load the RDB even if the module is not loaded.
7507	 * 
7508	 * Note: the module name "AAAAAAAAA" is reserved and produces an error, it
7509	 * happens to be pretty lame as well.
7510	 *
7511	 * If RedisModule_CreateDataType() is called outside of RedisModule_OnLoad() function,
7512	 * there is already a module registering a type with the same name,
7513	 * or if the module name or encver is invalid, NULL is returned.
7514	 * Otherwise the new type is registered into Redis, and a reference of
7515	 * type RedisModuleType is returned: the caller of the function should store
7516	 * this reference into a global variable to make future use of it in the
7517	 * modules type API, since a single module may register multiple types.
7518	 * Example code fragment:
7519	 *
7520	 *      static RedisModuleType *BalancedTreeType;
7521	 *
7522	 *      int RedisModule_OnLoad(RedisModuleCtx *ctx) {
7523	 *          // some code here ...
7524	 *          BalancedTreeType = RM_CreateDataType(...);
7525	 *      }
7526	 */
7527	moduleType *RM_CreateDataType(RedisModuleCtx *ctx, const char *name, int encver, void *typemethods_ptr) {
7528	    if (!ctx->module->onload)
7529	        return NULL;
7530	    uint64_t id = moduleTypeEncodeId(name,encver);
7531	    if (id == 0) return NULL;
7532	    if (moduleTypeLookupModuleByName(name) != NULL) return NULL;
7533	
7534	    long typemethods_version = ((long*)typemethods_ptr)[0];
7535	    if (typemethods_version == 0) return NULL;
7536	
7537	    struct typemethods {
7538	        uint64_t version;
7539	        moduleTypeLoadFunc rdb_load;
7540	        moduleTypeSaveFunc rdb_save;
7541	        moduleTypeRewriteFunc aof_rewrite;
7542	        moduleTypeMemUsageFunc mem_usage;
7543	        moduleTypeDigestFunc digest;
7544	        moduleTypeFreeFunc free;
7545	        struct {
7546	            moduleTypeAuxLoadFunc aux_load;
7547	            moduleTypeAuxSaveFunc aux_save;
7548	            int aux_save_triggers;
7549	        } v2;
7550	        struct {
7551	            moduleTypeFreeEffortFunc free_effort;
7552	            moduleTypeUnlinkFunc unlink;
7553	            moduleTypeCopyFunc copy;
7554	            moduleTypeDefragFunc defrag;
7555	        } v3;
7556	        struct {
7557	            moduleTypeMemUsageFunc2 mem_usage2;
7558	            moduleTypeFreeEffortFunc2 free_effort2;
7559	            moduleTypeUnlinkFunc2 unlink2;
7560	            moduleTypeCopyFunc2 copy2;
7561	        } v4;
7562	        struct {
7563	            moduleTypeAuxSaveFunc aux_save2;
7564	        } v5;
7565	    } *tms = (struct typemethods*) typemethods_ptr;
7566	
7567	    moduleType *mt = zcalloc(sizeof(*mt));
7568	    mt->entity.id = id;
7569	    mt->entity.module = ctx->module;
7570	    mt->rdb_load = tms->rdb_load;
7571	    mt->rdb_save = tms->rdb_save;
7572	    mt->aof_rewrite = tms->aof_rewrite;
7573	    mt->mem_usage = tms->mem_usage;
7574	    mt->digest = tms->digest;
7575	    mt->free = tms->free;
7576	    if (tms->version >= 2) {
7577	        mt->aux_load = tms->v2.aux_load;
7578	        mt->aux_save = tms->v2.aux_save;
7579	        mt->aux_save_triggers = tms->v2.aux_save_triggers;
7580	    }
7581	    if (tms->version >= 3) {
7582	        mt->free_effort = tms->v3.free_effort;
7583	        mt->unlink = tms->v3.unlink;
7584	        mt->copy = tms->v3.copy;
7585	        mt->defrag = tms->v3.defrag;
7586	    }
7587	    if (tms->version >= 4) {
7588	        mt->mem_usage2 = tms->v4.mem_usage2;
7589	        mt->unlink2 = tms->v4.unlink2;
7590	        mt->free_effort2 = tms->v4.free_effort2;
7591	        mt->copy2 = tms->v4.copy2;
7592	    }
7593	    if (tms->version >= 5) {
7594	        mt->aux_save2 = tms->v5.aux_save2;
7595	    }
7596	    memcpy(mt->entity.name,name,sizeof(mt->entity.name));
7597	    listAddNodeTail(ctx->module->types,mt);
7598	    return mt;
7599	}
