7645	/* Called when there is a load error in the context of a module. On some
7646	 * modules this cannot be recovered, but if the module declared capability
7647	 * to handle errors, we'll raise a flag rather than exiting. */
7648	void moduleRDBLoadError(RedisModuleIO *io) {
7649	    if (io->entity->module->options & REDISMODULE_OPTIONS_HANDLE_IO_ERRORS) {
7650	        io->error = 1;
7651	        return;
7652	    }
7653	    serverPanic(
7654	        "Error loading data from RDB (short read or EOF). "
7655	        "Read performed by module '%s' about type '%s' "
7656	        "after reading '%llu' bytes of a value "
7657	        "for key named: '%s'.",
7658	        io->entity->module->name,
7659	        io->entity->name,
7660	        (unsigned long long)io->bytes,
7661	        io->key? (char*)io->key->ptr: "(null)");
7662	}
7663	
7664	/* Returns 0 if there's at least one registered data type that did not declare
7665	 * REDISMODULE_OPTIONS_HANDLE_IO_ERRORS, in which case diskless loading should
7666	 * be avoided since it could cause data loss. */
7667	int moduleAllDatatypesHandleErrors(void) {
7668	    dictIterator di;
7669	    dictEntry *de;
7670	
7671	    dictInitIterator(&di, modules);
7672	    while ((de = dictNext(&di)) != NULL) {
7673	        struct RedisModule *module = dictGetVal(de);
7674	        if (listLength(module->types) &&
7675	            !(module->options & REDISMODULE_OPTIONS_HANDLE_IO_ERRORS))
7676	        {
7677	            dictResetIterator(&di);
7678	            return 0;
7679	        }
7680	    }
7681	    dictResetIterator(&di);
7682	    return 1;
7683	}
7684	
7685	/* Returns 0 if module did not declare REDISMODULE_OPTIONS_HANDLE_REPL_ASYNC_LOAD, in which case
7686	 * diskless async loading should be avoided because module doesn't know there can be traffic during
7687	 * database full resynchronization. */
7688	int moduleAllModulesHandleReplAsyncLoad(void) {
7689	    dictIterator di;
7690	    dictEntry *de;
7691	
7692	    dictInitIterator(&di, modules);
7693	    while ((de = dictNext(&di)) != NULL) {
7694	        struct RedisModule *module = dictGetVal(de);
7695	        if (!(module->options & REDISMODULE_OPTIONS_HANDLE_REPL_ASYNC_LOAD)) {
7696	            dictResetIterator(&di);
7697	            return 0;
7698	        }
7699	    }
7700	    dictResetIterator(&di);
7701	    return 1;
7702	}
