7711	static int flushRedisModuleIOBuffer(RedisModuleIO *io) {
7712	    if (!io->pre_flush_buffer) return 0;
7713	
7714	    /* We have data that must be flushed before saving the current data.
7715	     * Lets flush it. */
7716	    sds pre_flush_buffer = io->pre_flush_buffer;
7717	    io->pre_flush_buffer = NULL;
7718	    ssize_t retval = rdbWriteRaw(io->rio, pre_flush_buffer, sdslen(pre_flush_buffer));
7719	    sdsfree(pre_flush_buffer);
7720	    if (retval >= 0) io->bytes += retval;
7721	    return retval;
7722	}
