7724	/* Save an unsigned 64 bit value into the RDB file. This function should only
7725	 * be called in the context of the rdb_save method of modules implementing new
7726	 * data types. */
7727	void RM_SaveUnsigned(RedisModuleIO *io, uint64_t value) {
7728	    if (io->error) return;
7729	    if (flushRedisModuleIOBuffer(io) == -1) goto saveerr;
7730	    /* Save opcode. */
7731	    int retval = rdbSaveLen(io->rio, RDB_MODULE_OPCODE_UINT);
7732	    if (retval == -1) goto saveerr;
7733	    io->bytes += retval;
7734	    /* Save value. */
7735	    retval = rdbSaveLen(io->rio, value);
7736	    if (retval == -1) goto saveerr;
7737	    io->bytes += retval;
7738	    return;
7739	
7740	saveerr:
7741	    io->error = 1;
7742	}
