7744	/* Load an unsigned 64 bit value from the RDB file. This function should only
7745	 * be called in the context of the `rdb_load` method of modules implementing
7746	 * new data types. */
7747	uint64_t RM_LoadUnsigned(RedisModuleIO *io) {
7748	    if (io->error) return 0;
7749	    uint64_t opcode = rdbLoadLen(io->rio,NULL);
7750	    if (opcode != RDB_MODULE_OPCODE_UINT) goto loaderr;
7751	    uint64_t value;
7752	    int retval = rdbLoadLenByRef(io->rio, NULL, &value);
7753	    if (retval == -1) goto loaderr;
7754	    return value;
7755	
7756	loaderr:
7757	    moduleRDBLoadError(io);
7758	    return 0;
7759	}
