7761	/* Like RedisModule_SaveUnsigned() but for signed 64 bit values. */
7762	void RM_SaveSigned(RedisModuleIO *io, int64_t value) {
7763	    union {uint64_t u; int64_t i;} conv;
7764	    conv.i = value;
7765	    RM_SaveUnsigned(io,conv.u);
7766	}
