7768	/* Like RedisModule_LoadUnsigned() but for signed 64 bit values. */
7769	int64_t RM_LoadSigned(RedisModuleIO *io) {
7770	    union {uint64_t u; int64_t i;} conv;
7771	    conv.u = RM_LoadUnsigned(io);
7772	    return conv.i;
