7928	/* In the context of the rdb_save method of a module data type, saves a long double
7929	 * value to the RDB file. The double can be a valid number, a NaN or infinity.
7930	 * It is possible to load back the value with RedisModule_LoadLongDouble(). */
7931	void RM_SaveLongDouble(RedisModuleIO *io, long double value) {
7932	    if (io->error) return;
7933	    char buf[MAX_LONG_DOUBLE_CHARS];
7934	    /* Long double has different number of bits in different platforms, so we
7935	     * save it as a string type. */
7936	    size_t len = ld2string(buf,sizeof(buf),value,LD_STR_HEX);
7937	    RM_SaveStringBuffer(io,buf,len);
7938	}
