7940	/* In the context of the rdb_save method of a module data type, loads back the
7941	 * long double value saved by RedisModule_SaveLongDouble(). */
7942	long double RM_LoadLongDouble(RedisModuleIO *io) {
7943	    if (io->error) return 0;
7944	    long double value;
7945	    size_t len;
7946	    char* str = RM_LoadStringBuffer(io,&len);
7947	    if (!str) return 0;
7948	    string2ld(str,len,&value);
7949	    RM_Free(str);
7950	    return value;
7951	}
