7953	/* Iterate over modules, and trigger rdb aux saving for the ones modules types
7954	 * who asked for it. */
7955	ssize_t rdbSaveModulesAux(rio *rdb, int when) {
7956	    size_t total_written = 0;
7957	    dictIterator di;
7958	    dictEntry *de;
7959	
7960	    dictInitIterator(&di, modules);
7961	    while ((de = dictNext(&di)) != NULL) {
7962	        struct RedisModule *module = dictGetVal(de);
7963	        listIter li;
7964	        listNode *ln;
7965	
7966	        listRewind(module->types,&li);
7967	        while((ln = listNext(&li))) {
7968	            moduleType *mt = ln->value;
7969	            if ((!mt->aux_save && !mt->aux_save2) || !(mt->aux_save_triggers & when))
7970	                continue;
7971	            ssize_t ret = rdbSaveSingleModuleAux(rdb, when, mt);
7972	            if (ret==-1) {
7973	                dictResetIterator(&di);
7974	                return -1;
7975	            }
7976	            total_written += ret;
7977	        }
7978	    }
7979	
7980	    dictResetIterator(&di);
7981	    return total_written;
7982	}
