5381	    for (int j = 0; j<num_args; j++) {
5382	        /* Count our reply len so we don't have to use deferred reply. */
5383	        int has_display_text = 1;
5384	        long maplen = 2;
5385	        if (args[j].key_spec_index != -1) maplen++;
5386	        if (args[j].token) maplen++;
5387	        if (args[j].summary) maplen++;
5388	        if (args[j].since) maplen++;
5389	        if (args[j].deprecated_since) maplen++;
5390	        if (args[j].flags) maplen++;
5391	        if (args[j].type == ARG_TYPE_ONEOF || args[j].type == ARG_TYPE_BLOCK) {
5392	            has_display_text = 0;
5393	            maplen++;
5394	        }
5395	        if (has_display_text) maplen++;
5396	        addReplyMapLen(c, maplen);
5397	
5398	        addReplyBulkCString(c, "name");
5399	        addReplyBulkCString(c, args[j].name);
5400	
5401	        addReplyBulkCString(c, "type");
5402	        addReplyBulkCString(c, ARG_TYPE_STR[args[j].type]);
5403	
5404	        if (has_display_text) {
5405	            addReplyBulkCString(c, "display_text");
5406	            addReplyBulkCString(c, args[j].display_text ? args[j].display_text : args[j].name);
5407	        }
