2026	/* Save the DB on disk. Return C_ERR on error, C_OK on success. */
2027	int rdbSave(int req, char *filename, rdbSaveInfo *rsi, int rdbflags) {
2028	    char tmpfile[256];
2029	    char cwd[MAXPATHLEN]; /* Current working dir path for error messages. */
2030	
2031	    startSaving(rdbflags);
2032	    snprintf(tmpfile,256,"temp-%d.rdb", (int) getpid());
2033	
2034	    if (rdbSaveInternal(req,tmpfile,rsi,rdbflags) != C_OK) {
2035	        stopSaving(0);
2036	        return C_ERR;
2037	    }
2038	    
2039	    /* Use RENAME to make sure the DB file is changed atomically only
2040	     * if the generate DB file is ok. */
2041	    if (rename(tmpfile,filename) == -1) {
2042	        char *str_err = strerror(errno);
2043	        char *cwdp = getcwd(cwd,MAXPATHLEN);
2044	        serverLog(LL_WARNING,
2045	            "Error moving temp DB file %s on the final "
2046	            "destination %s (in server root dir %s): %s",
2047	            tmpfile,
2048	            filename,
2049	            cwdp ? cwdp : "unknown",
2050	            str_err);
2051	        unlink(tmpfile);
2052	        stopSaving(0);
2053	        return C_ERR;
