2131	/* This function is called by rdbLoadObject() when the code is in RDB-check
2132	 * mode and we find a module value of type 2 that can be parsed without
2133	 * the need of the actual module. The value is parsed for errors.
2134	 * If null_on_error is true, NULL is returned when data corruption is detected;
2135	 * otherwise a dummy redis object is always returned regardless of success or
2136	 * failure. */
2137	robj *rdbLoadCheckModuleValue(rio *rdb, char *modulename, int null_on_error) {
2138	    uint64_t opcode;
2139	    while((opcode = rdbLoadLen(rdb,NULL)) != RDB_MODULE_OPCODE_EOF) {
2140	        if (opcode == RDB_LENERR) {
2141	            rdbReportCorruptRDB("Error reading module opcode length from module %s value", modulename);
2142	            goto error;
2143	        }
2144	
2145	        if (opcode == RDB_MODULE_OPCODE_SINT ||
2146	            opcode == RDB_MODULE_OPCODE_UINT)
2147	        {
2148	            uint64_t len;
2149	            if (rdbLoadLenByRef(rdb,NULL,&len) == -1) {
2150	                rdbReportCorruptRDB(
2151	                    "Error reading integer from module %s value", modulename);
2152	                goto error;
2153	            }
2154	        } else if (opcode == RDB_MODULE_OPCODE_STRING) {
2155	            robj *o = rdbGenericLoadStringObject(rdb,RDB_LOAD_NONE,NULL);
2156	            if (o == NULL) {
2157	                rdbReportCorruptRDB(
2158	                    "Error reading string from module %s value", modulename);
2159	                goto error;
2160	            }
2161	            decrRefCount(o);
2162	        } else if (opcode == RDB_MODULE_OPCODE_FLOAT) {
2163	            float val;
2164	            if (rdbLoadBinaryFloatValue(rdb,&val) == -1) {
2165	                rdbReportCorruptRDB(
2166	                    "Error reading float from module %s value", modulename);
2167	                goto error;
2168	            }
2169	        } else if (opcode == RDB_MODULE_OPCODE_DOUBLE) {
2170	            double val;
2171	            if (rdbLoadBinaryDoubleValue(rdb,&val) == -1) {
2172	                rdbReportCorruptRDB(
2173	                    "Error reading double from module %s value", modulename);
2174	                goto error;
2175	            }
2176	        } else {
2177	            rdbReportCorruptRDB(
2178	                "Unknown module opcode %llu reading module %s value", (unsigned long long)opcode, modulename);
2179	            goto error;
2180	        }
2181	    }
2182	    return createStringObject("module-dummy-value",18);
2183	error:
2184	    return null_on_error ? NULL : createStringObject("module-dummy-value",18);
2185	}
