2218	/* callback for hashZiplistConvertAndValidateIntegrity.
2219	 * Check that the ziplist doesn't have duplicate hash field names.
2220	 * The ziplist element pointed by 'p' will be converted and stored into listpack. */
2221	static int _ziplistPairsEntryConvertAndValidate(unsigned char *p, unsigned int head_count, void *userdata) {
2222	    unsigned char *str;
2223	    unsigned int slen;
2224	    long long vll;
2225	
2226	    struct {
2227	        long count;
2228	        dict *fields;
2229	        unsigned char **lp;
2230	    } *data = userdata;
2231	
2232	    if (data->fields == NULL) {
2233	        data->fields = dictCreate(&hashDictType);
2234	        dictExpand(data->fields, head_count/2);
2235	    }
2236	
2237	    if (!ziplistGet(p, &str, &slen, &vll))
2238	        return 0;
2239	
2240	    /* Even records are field names, add to dict and check that's not a dup */
2241	    if (((data->count) & 1) == 0) {
2242	        sds field = str? sdsnewlen(str, slen): sdsfromlonglong(vll);
2243	        if (dictAdd(data->fields, field, NULL) != DICT_OK) {
2244	            /* Duplicate, return an error */
2245	            sdsfree(field);
2246	            return 0;
2247	        }
2248	    }
2249	
2250	    if (str) {
2251	        *(data->lp) = lpAppend(*(data->lp), (unsigned char*)str, slen);
2252	    } else {
2253	        *(data->lp) = lpAppendInteger(*(data->lp), vll);
2254	    }
2255	
2256	    (data->count)++;
2257	    return 1;
2258	}
