2261	 * listpack and storing it at 'lp'.
2262	 * The function is safe to call on non-validated ziplists, it returns 0
2263	 * when encounter an integrity validation issue. */
2264	int ziplistPairsConvertAndValidateIntegrity(unsigned char *zl, size_t size, unsigned char **lp) {
2265	    /* Keep track of the field names to locate duplicate ones */
2266	    struct {
