2321	/* callback for to check the listpack doesn't have duplicate records */
2322	static int _lpEntryValidation(unsigned char *p, unsigned int head_count, void *userdata) {
2323	    struct {
2324	        int tuple_len;
2325	        long count;
2326	        dict *fields;
2327	        long long last_expireat;
2328	    } *data = userdata;
2329	
2330	    if (data->fields == NULL) {
2331	        data->fields = dictCreate(&hashDictType);
2332	        dictExpand(data->fields, head_count/data->tuple_len);
2333	    }
2334	
2335	    /* If we're checking pairs, then even records are field names. Otherwise
2336	     * we're checking all elements. Add to dict and check that's not a dup */
2337	    if (data->count % data->tuple_len == 0) {
2338	        unsigned char *str;
2339	        int64_t slen;
2340	        unsigned char buf[LP_INTBUF_SIZE];
2341	
2342	        str = lpGet(p, &slen, buf);
2343	        sds field = sdsnewlen(str, slen);
2344	        if (dictAdd(data->fields, field, NULL) != DICT_OK) {
2345	            /* Duplicate, return an error */
2346	            sdsfree(field);
2347	            return 0;
2348	        }
2349	    }
2350	
2351	    /* Validate TTL field, only for listpackex. */
2352	    if (data->count % data->tuple_len == 2) {
2353	        long long expire_at;
2354	        /* Must be an integer. */
2355	        if (!lpGetIntegerValue(p, &expire_at)) return 0;
2356	        /* Must be less than EB_EXPIRE_TIME_MAX. */
2357	        if (expire_at < 0 || (unsigned long long)expire_at > EB_EXPIRE_TIME_MAX) return 0;
2358	        /* TTL fields are ordered. If the current field has TTL, the previous field must
2359	         * also have one, and the current TTL must be greater than the previous one. */
2360	        if (expire_at != 0 && (data->last_expireat == 0 || expire_at < data->last_expireat)) return 0;
2361	        data->last_expireat = expire_at;
2362	    }
2363	
2364	    (data->count)++;
2365	    return 1;
2366	}
