2368	/* Validate the integrity of the listpack structure.
2369	 * when `deep` is 0, only the integrity of the header is validated.
2370	 * when `deep` is 1, we scan all the entries one by one.
2371	 * tuple_len indicates what is a logical entry tuple size.
2372	 * Whether tuple is of size 1 (set), 2 (feild-value) or 3 (field-value[-ttl]),
2373	 * first element in the tuple must be unique */
2374	int lpValidateIntegrityAndDups(unsigned char *lp, size_t size, int deep, int tuple_len) {
2375	    if (!deep)
2376	        return lpValidateIntegrity(lp, size, 0, NULL, NULL);
2377	
2378	    /* Keep track of the field names to locate duplicate ones */
2379	    struct {
2380	        int tuple_len;
2381	        long count;
2382	        dict *fields; /* Initialisation at the first callback. */
2383	        long long last_expireat; /* Last field's expiry time to ensure order in TTL fields. */
2384	    } data = {tuple_len, 0, NULL, -1};
2385	
2386	    int ret = lpValidateIntegrity(lp, size, 1, _lpEntryValidation, &data);
2387	
2388	    /* the number of records should be a multiple of the tuple length */
2389	    if (data.count % tuple_len != 0)
2390	        ret = 0;
2391	
2392	    if (data.fields) dictRelease(data.fields);
2393	    return ret;
2394	}
