2415	    int deep_integrity_validation = server.sanitize_dump_payload == SANITIZE_DUMP_YES;
2416	    if (server.sanitize_dump_payload == SANITIZE_DUMP_CLIENTS) {
2417	        /* Skip sanitization when loading (an RDB), or getting a RESTORE command
2418	         * from either the master or a client using an ACL user with the skip-sanitize-payload flag. */
2419	        int skip = server.loading ||
2420	            (server.current_client && (server.current_client->flags & CLIENT_MASTER));
2421	        if (!skip && server.current_client && server.current_client->user)
2422	            skip = !!(server.current_client->user->flags & USER_FLAG_SANITIZE_PAYLOAD_SKIP);
2423	        deep_integrity_validation = !skip;
2424	    }
