2427	        /* Read string value */
2428	        if ((o = rdbLoadEncodedStringObject(rdb)) == NULL) return NULL;
2429	        o = tryObjectEncodingEx(o, 0);
2430	    } else if (rdbtype == RDB_TYPE_LIST) {
2431	        /* Read list value */
2432	        if ((len = rdbLoadLen(rdb,NULL)) == RDB_LENERR) return NULL;
2433	        if (len == 0) goto emptykey;
2434	
2435	        o = createQuicklistObject(server.list_max_listpack_size, server.list_compress_depth);
2436	
