2456	        /* Use a regular set when there are too many entries. */
2457	        size_t max_entries = server.set_max_intset_entries;
2458	        if (max_entries >= 1<<30) max_entries = 1<<30;
2459	        if (len > max_entries) {
2460	            o = createSetObject();
2461	            /* It's faster to expand the dict to the right size asap in order
2462	             * to avoid rehashing */
