2467	            }
2468	        } else {
2469	            o = createIntsetObject();
2470	        }
2471	
2472	        /* Load every single element of the set */
2473	        size_t maxelelen = 0, sumelelen = 0;
2474	        for (i = 0; i < len; i++) {
2475	            long long llval;
2476	            sds sdsele;
2477	
2478	            if ((sdsele = rdbGenericLoadStringObject(rdb,RDB_LOAD_SDS,NULL)) == NULL) {
2479	                decrRefCount(o);
2480	                return NULL;
2481	            }
2482	            size_t elelen = sdslen(sdsele);
2483	            sumelelen += elelen;
2484	            if (elelen > maxelelen) maxelelen = elelen;
2485	
2486	            if (o->encoding == OBJ_ENCODING_INTSET) {
2487	                /* Fetch integer value from element. */
2488	                if (isSdsRepresentableAsLongLong(sdsele,&llval) == C_OK) {
2489	                    uint8_t success;
2490	                    o->ptr = intsetAdd(o->ptr, llval, &success);
2491	                    if (!success) {
2492	                        rdbReportCorruptRDB("Duplicate set members detected");
2493	                        decrRefCount(o);
2494	                        sdsfree(sdsele);
2495	                        return NULL;
2496	                    }
2497	                } else if (setTypeSize(o) < server.set_max_listpack_entries &&
2498	                           maxelelen <= server.set_max_listpack_value &&
2499	                           lpSafeToAdd(NULL, sumelelen))

1000	    if (kill(server.child_pid,SIGUSR1) != -1) {
1001	        while(waitpid(-1, &statloc, 0) != server.child_pid);
1002	    }
1003	    aofRemoveTempFile(server.child_pid);
1004	    resetChildState();
1005	    server.aof_rewrite_time_start = -1;
1006	}
