64	static void addDictIndexToCursor(kvstore *kvs, int didx, unsigned long long *cursor) {
65	    if (kvs->num_dicts == 1)
66	        return;
67	    /* didx can be -1 when iteration is over and there are no more dicts to visit. */
68	    if (didx < 0)
69	        return;
70	    *cursor = (*cursor << kvs->num_dicts_bits) | didx;
71	}
