73	static int getAndClearDictIndexFromCursor(kvstore *kvs, unsigned long long *cursor) {
74	    if (kvs->num_dicts == 1)
75	        return 0;
76	    int didx = (int) (*cursor & (kvs->num_dicts-1));
77	    *cursor = *cursor >> kvs->num_dicts_bits;
78	    return didx;
79	}
