81	/* Updates binary index tree (Fenwick tree), updates key count for a given dict */
82	static void cumulativeKeyCountAdd(kvstore *kvs, int didx, long delta) {
83	    kvs->key_count += delta;
84	
85	    dict *d = kvstoreGetDict(kvs, didx);
86	    size_t dsize = dictSize(d);
87	    /* Increment if dsize is 1 and delta is positive (first element inserted, dict becomes non-empty).
88	     * Decrement if dsize is 0 (dict becomes empty). */
89	    int non_empty_dicts_delta = (dsize == 1 && delta > 0) ? 1 : (dsize == 0) ? -1 : 0;
90	    kvs->non_empty_dicts += non_empty_dicts_delta;
91	
92	    /* BIT does not need to be calculated when there's only one dict. */
93	    if (kvs->num_dicts == 1)
94	        return;
95	
96	    /* Update the BIT */
97	    fwTreeUpdate(kvs->dict_sizes, didx, delta);
98	}
