114	 * Note that for rehashing dicts, that is, in the case of safe iterators
115	 * and Scan, we won't delete the dict. We will check whether it needs
116	 * to be deleted when we're releasing the iterator. */
117	static void freeDictIfNeeded(kvstore *kvs, int didx) {
118	    if (!(kvs->flags & KVSTORE_FREE_EMPTY_DICTS) ||
119	        !kvstoreGetDict(kvs, didx) ||
120	        kvstoreDictSize(kvs, didx) != 0 ||
121	        kvstoreDictIsRehashingPaused(kvs, didx))
122	        return;
123	
124	    /* Use callback if provided to check if dict can be freed */
125	    if (kvs->type->canFreeDict && !kvs->type->canFreeDict(kvs, didx))
126	        return;
127	
128	    dictRelease(kvs->dicts[didx]);
129	    kvs->dicts[didx] = NULL;
130	    kvs->allocated_dicts--;
131	}
