141	/* Adds dictionary to the rehashing list, which allows us
142	 * to quickly find rehash targets during incremental rehashing.
143	 *
144	 * If there are multiple dicts, updates the bucket count for the given dictionary
145	 * in a DB, bucket count incremented with the new ht size during the rehashing phase.
146	 * If there's one dict, bucket count can be retrieved directly from single dict bucket. */
147	static void kvstoreDictRehashingStarted(dict *d) {
148	    kvstore *kvs = d->type->userdata;
149	    kvstoreDictMetaBase *metadata = (kvstoreDictMetaBase *)dictMetadata(d);
150	    listAddNodeTail(kvs->rehashing, d);
151	    metadata->rehashing_node = listLast(kvs->rehashing);
152	
153	    unsigned long long from, to;
154	    dictRehashingInfo(d, &from, &to);
155	    kvs->overhead_hashtable_rehashing += from;
156	}
