158	/* Remove dictionary from the rehashing list.
159	 *
160	 * Updates the bucket count for the given dictionary in a DB. It removes
161	 * the old ht size of the dictionary from the total sum of buckets for a DB.  */
162	static void kvstoreDictRehashingCompleted(dict *d) {
163	    kvstore *kvs = d->type->userdata;
164	    kvstoreDictMetaBase *metadata = (kvstoreDictMetaBase *)dictMetadata(d);
165	    if (metadata->rehashing_node) {
166	        listDelNode(kvs->rehashing, metadata->rehashing_node);
167	        metadata->rehashing_node = NULL;
168	    }
169	
170	    unsigned long long from, to;
171	    dictRehashingInfo(d, &from, &to);
172	    kvs->overhead_hashtable_rehashing -= from;
173	}
