175	/* Updates the bucket count for the given dictionary in a DB. It adds the new ht size
176	 * of the dictionary or removes the old ht size of the dictionary from the total
177	 * sum of buckets for a DB. */
178	static void kvstoreDictBucketChanged(dict *d, long long delta) {
179	    kvstore *kvs = d->type->userdata;
180	    kvs->bucket_count += delta;
181	}
