193	/* Create an array of dictionaries
194	 * num_dicts_bits is the log2 of the amount of dictionaries needed (e.g. 0 for 1 dict,
195	 * 3 for 8 dicts, etc.) */
196	kvstore *kvstoreCreate(kvstoreType *type, dictType *dtype, int num_dicts_bits, int flags) {
197	    /* We can't support more than 2^16 dicts because we want to save 48 bits
198	     * for the dict cursor, see kvstoreScan */
199	    assert(num_dicts_bits <= 16);
200	    assert(!type->dictMetadataBytes || type->dictMetadataBytes(NULL) >= sizeof(kvstoreDictMetaBase));
201	
202	    /* Calc kvstore size */   
203	    size_t kvsize = sizeof(kvstore);
204	    /* Conditionally calc also histogram size */
205	    if (type->kvstoreMetadataBytes)
206	        kvsize += type->kvstoreMetadataBytes(NULL);
207	    
208	    kvstore *kvs = zcalloc(kvsize);
209	    memcpy(&kvs->dtype, dtype, sizeof(kvs->dtype));
210	    kvs->flags = flags;
211	    kvs->type = type;
212	
213	    /* kvstore must be the one to set these callbacks, so we make sure the
214	     * caller didn't do it */
215	    assert(!dtype->userdata);
216	    assert(!dtype->dictMetadataBytes);
217	    assert(!dtype->rehashingStarted);
218	    assert(!dtype->rehashingCompleted);
219	    kvs->dtype.userdata = kvs;
220	    kvs->dtype.dictMetadataBytes = type->dictMetadataBytes ?
221	        type->dictMetadataBytes : kvstoreDictBaseMetaSize;
222	    kvs->dtype.rehashingStarted = kvstoreDictRehashingStarted;
223	    kvs->dtype.rehashingCompleted = kvstoreDictRehashingCompleted;
224	    kvs->dtype.bucketChanged = kvstoreDictBucketChanged;
225	
226	    kvs->num_dicts_bits = num_dicts_bits;
227	    kvs->num_dicts = 1 << kvs->num_dicts_bits;
228	    kvs->dicts = zcalloc(sizeof(dict*) * kvs->num_dicts);
229	    if (!(kvs->flags & KVSTORE_ALLOCATE_DICTS_ON_DEMAND)) {
230	        for (int i = 0; i < kvs->num_dicts; i++)
231	            createDictIfNeeded(kvs, i);
232	    }
233	
234	    kvs->rehashing = listCreate();
235	    kvs->key_count = 0;
236	    kvs->non_empty_dicts = 0;
237	    kvs->resize_cursor = 0;
238	    kvs->dict_sizes = kvs->num_dicts > 1 ? fwTreeCreate(kvs->num_dicts_bits) : NULL;
239	    kvs->bucket_count = 0;
240	    kvs->overhead_hashtable_rehashing = 0;
241	    return kvs;
242	}
