244	void kvstoreEmpty(kvstore *kvs, void(callback)(dict*)) {
245	    for (int didx = 0; didx < kvs->num_dicts; didx++) {
246	        dict *d = kvstoreGetDict(kvs, didx);
247	        if (!d)
248	            continue;
249	        kvstoreDictMetaBase *metadata = (kvstoreDictMetaBase *)dictMetadata(d);
250	        if (metadata->rehashing_node)
251	            metadata->rehashing_node = NULL;
252	        dictEmpty(d, callback);
253	        if (kvs->type->onDictEmpty) kvs->type->onDictEmpty(kvs, didx);
254	        freeDictIfNeeded(kvs, didx);
255	    }
256	
257	    if (kvs->type->onKvstoreEmpty) kvs->type->onKvstoreEmpty(kvs);
258	
259	    listEmpty(kvs->rehashing);
260	
261	    kvs->key_count = 0;
262	    kvs->non_empty_dicts = 0;
263	    kvs->resize_cursor = 0;
264	    kvs->bucket_count = 0;
265	    if (kvs->dict_sizes)
266	        fwTreeClear(kvs->dict_sizes);
267	    kvs->overhead_hashtable_rehashing = 0;
