304	size_t kvstoreMemUsage(kvstore *kvs) {
305	    size_t mem = sizeof(*kvs);
306	    size_t metaSize = kvs->dtype.dictMetadataBytes(NULL);
307	    unsigned long long keys_count = kvstoreSize(kvs);
