318	/*
319	 * This method is used to iterate over the elements of the entire kvstore specifically across dicts.
320	 * It's a three pronged approach.
321	 *
322	 * 1. It uses the provided cursor `cursor` to retrieve the dict index from it.
323	 * 2. If the dictionary is in a valid state checked through the provided callback `dictScanValidFunction`,
324	 *    it performs a dictScan over the appropriate `keyType` dictionary of `db`.
325	 * 3. If the dict is entirely scanned i.e. the cursor has reached 0, the next non empty dict is discovered.
326	 *    The dict information is embedded into the cursor and returned.
327	 *
328	 * To restrict the scan to a single dict, pass a valid dict index as
329	 * 'onlydidx', otherwise pass -1.
330	 */
331	unsigned long long kvstoreScan(kvstore *kvs, unsigned long long cursor,
332	                               int onlydidx, dictScanFunction *scan_cb,
333	                               kvstoreScanShouldSkipDict *skip_cb,
334	                               void *privdata)
335	{
336	    unsigned long long _cursor = 0;
337	    /* During dictionary traversal, 48 upper bits in the cursor are used for positioning in the HT.
338	     * Following lower bits are used for the dict index number, ranging from 0 to 2^num_dicts_bits-1.
339	     * Dict index is always 0 at the start of iteration and can be incremented only if there are
340	     * multiple dicts. */
341	    int didx = getAndClearDictIndexFromCursor(kvs, &cursor);
342	    if (onlydidx >= 0) {
343	        if (didx < onlydidx) {
344	            /* Fast-forward to onlydidx. */
345	            assert(onlydidx < kvs->num_dicts);
346	            didx = onlydidx;
347	            cursor = 0;
348	        } else if (didx > onlydidx) {
349	            /* The cursor is already past onlydidx. */
350	            return 0;
351	        }
352	    }
353	
354	    dict *d = kvstoreGetDict(kvs, didx);
355	
356	    int skip = !d || (skip_cb && skip_cb(d, didx));
357	    if (!skip) {
358	        _cursor = dictScan(d, cursor, scan_cb, privdata);
359	        /* In dictScan, scan_cb may delete entries (e.g., in active expire case). */
360	        freeDictIfNeeded(kvs, didx);
361	    }
362	    /* scanning done for the current dictionary or if the scanning wasn't possible, move to the next dict index. */
363	    if (_cursor == 0 || skip) {
364	        if (onlydidx >= 0)
365	            return 0;
366	        didx = kvstoreGetNextNonEmptyDictIndex(kvs, didx);
367	    }
368	    if (didx == -1) {
369	        return 0;
370	    }
371	    addDictIndexToCursor(kvs, didx, &_cursor);
372	    return _cursor;
373	}
