375	/*
376	 * This functions increases size of kvstore to match desired number.
377	 * It resizes all individual dictionaries, unless skip_cb indicates otherwise.
378	 *
379	 * Based on the parameter `try_expand`, appropriate dict expand API is invoked.
380	 * if try_expand is set to 1, `dictTryExpand` is used else `dictExpand`.
381	 * The return code is either `DICT_OK`/`DICT_ERR` for both the API(s).
382	 * `DICT_OK` response is for successful expansion. However, `DICT_ERR` response signifies failure in allocation in
383	 * `dictTryExpand` call and in case of `dictExpand` call it signifies no expansion was performed.
384	 */
385	int kvstoreExpand(kvstore *kvs, uint64_t newsize, int try_expand, kvstoreExpandShouldSkipDictIndex *skip_cb) {
386	    for (int i = 0; i < kvs->num_dicts; i++) {
387	        if (skip_cb && skip_cb(i)) continue;
388	        dict *d = createDictIfNeeded(kvs, i);
389	        if (!d) continue;
390	
391	        int result = try_expand ? dictTryExpand(d, newsize) : dictExpand(d, newsize);
392	        if (try_expand && result == DICT_ERR)
393	            return 0;
394	    }
395	
396	    return 1;
397	}
